INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('2a60aaf8-c316-591f-b53d-38d9a8885038', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Prayer for Emotional Healing', NULL, ARRAY[]::text[], 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('ba8a5e19-79ec-5765-b7c8-783738222870', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Prayer for Inner Wounds to be Healed', NULL, ARRAY[]::text[], 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('c184b3b3-bd6d-5de6-99cf-e6fafe5abd2a', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Restoration after Failure', NULL, ARRAY[]::text[], 4) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('c922c587-8f5b-542d-83aa-f7b57c6d0b4c', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Prayer for a Broken Heart', NULL, ARRAY[]::text[], 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('230869c0-59bc-5c6b-8e3f-5a761aa5d247', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Healing of Memories', NULL, ARRAY[]::text[], 6) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('429c4049-eb5f-5621-9a61-35b275e317c9', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Healing from Trauma', NULL, ARRAY[]::text[], 7) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('601c4a8f-8ce6-5652-af39-845234fe2e05', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Healing after Loss', NULL, ARRAY[]::text[], 8) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('0d5e1f05-11a0-5d22-bc30-49d98ea17f00', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Restoration of What the Enemy Stole', NULL, ARRAY[]::text[], 9) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayer_topics (id, theme_id, title, description, tags, sort_order) VALUES ('5c6bf6ca-475b-5f5b-9537-0618f08756d0', 'fd7649b4-11d8-5bee-a9f4-ca17e0717c43', 'Healing in Broken Relationships', NULL, ARRAY[]::text[], 10) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('38199e8c-6ed8-5d7e-8710-9001e99b72a3', '004f6f20-2b88-59ac-92e0-80fff3d59610', 'Praying Beyond My Words', 'Father, thank You that when I do not know how to pray, the Spirit Himself intercedes for me — with groanings too deep for words, He takes what I cannot express and brings it before You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dcd90d42-efba-5018-ba6a-8e07e254196b', '004f6f20-2b88-59ac-92e0-80fff3d59610', 'Interceding Through Me', 'Lord, I confess that I often come to prayer already knowing what I want to say, already convinced of what I need — and I leave little room for Your Spirit to redirect me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('381d4d4e-5378-592a-ae2f-e3be8f7979d6', '03c11844-175d-52ae-8335-03bbedc211a5', 'First Go and Be Reconciled', 'Father, You take reconciliation so seriously that You say to leave our offering at the altar and go be reconciled first — I feel the weight of that today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b30fb9fa-586a-5d76-bde2-2e5ec2138f54', '03c11844-175d-52ae-8335-03bbedc211a5', 'Restore What Was Broken', 'Lord, broken relationships carry a unique kind of grief — the loss of someone still living, the silence where there used to be warmth. I bring that grief to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3843bae1-1b98-57dc-83e5-1f0ca9e1efa6', '0469ef20-0394-5d85-bd69-a23ed05d82c4', 'Welcome One Another', 'Father, You tell me to welcome others as Christ has welcomed me — and I cannot do that well if I have not first received the welcome He offers me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ddfc9ae5-3a72-54b8-9813-cb2277b18c37', '0469ef20-0394-5d85-bd69-a23ed05d82c4', 'Already Accepted', 'Lord, You have accepted me just as Christ accepted me — fully, finally, freely — and I want to stop living as though that acceptance can be lost or needs to be earned back.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6d422d4a-e69f-5c2e-9e7b-7b97952c4c1e', '04ee7c61-8438-5a7f-ae95-ff6fdecb134a', 'He Guides the Humble', 'Father, Your Spirit leads those who belong to You — and I belong to You, which means this guidance is not something I have to earn or beg for but something You have committed to give.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b52c6377-e689-5397-be09-6a3b9f72f388', '04ee7c61-8438-5a7f-ae95-ff6fdecb134a', 'Sons and Daughters Are Led', 'Lord, those who are led by Your Spirit are sons and daughters of God — and I am Your child, which means being led by Your Spirit is both my birthright and my responsibility.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('21e363c7-4035-5985-a743-6353ad88b747', '050d9274-9b1a-5810-91da-d92d198ce8c5', 'Faithful in Little', 'Lord, if I have not been faithful with worldly wealth, who will trust me with true riches — I take that question seriously, and I ask You to help me be faithful with what You have entrusted to me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5f164842-afd8-5b77-b02d-e43b4b690996', '050d9274-9b1a-5810-91da-d92d198ce8c5', 'Honor the Lord with Your Wealth', 'Father, You are the source of every resource I have — the income, the abilities, the opportunities, the health that enables me to work — all of it comes from You and belongs to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ed81d79b-1c44-5775-a490-3fb8a44823e5', '05a2f8db-f051-54f9-b1ca-14ae806b0e43', 'Sitting in the Silence', 'Father, I confess that I am struggling — the silence feels like rejection, and I know in my mind it is not, but my heart is having trouble believing that right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('fd8c9fb7-3175-5973-b913-18f88b4a4ba6', '05a2f8db-f051-54f9-b1ca-14ae806b0e43', 'Where Are You, God?', 'God, I am crying out to You and the silence is deafening — I have prayed and prayed and it feels like no one is there, and I need You to know that this is breaking me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b8f313f9-ffd2-5854-b99f-c5d369e2bf88', '074a664d-4b8b-5713-9792-3e5bda895938', 'What Is Bound in Heaven', 'Lord Jesus, You gave Your disciples authority over all the power of the enemy, and You promised that nothing would harm them — I stand on that promise today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ea5cb4d0-191e-5011-ba2d-9b2f28d6c2f0', '074a664d-4b8b-5713-9792-3e5bda895938', 'No Place for the Enemy', 'Father, I come to You first — not to the enemy in fear, but to You in confidence — because You are Lord over every principality and power in heaven and on earth.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('36df388e-d0ae-530f-b100-7a1eee011af5', '07d66c1e-fe6b-550a-8dc2-78cc27f15e54', 'The God Who Lifts', 'Father, I have fallen — and I am not coming to You pretending otherwise. I bring this to You with full honesty, because You already know.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7303a306-76b6-551a-9bab-517d8d35a9bb', '07d66c1e-fe6b-550a-8dc2-78cc27f15e54', 'Receiving Mercy Again', 'Lord, I have been here before — this failure is not new, and the shame of that is part of what makes it heavy.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d294ea37-4207-5256-88d9-637c6a399e05', '07deeecd-88ba-50d4-a1d2-dbde393c6008', 'What Happens Behind Closed Doors', 'God, I am better at controlling my anger in public than I am at home — and that is a sign that the people I love most are getting the worst of me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('fe2d54f4-1683-5568-9500-f8b9ec59cc4e', '07deeecd-88ba-50d4-a1d2-dbde393c6008', 'When I''ve Wounded the Ones I Love', 'Father, I have wounded people under my own roof with my anger — and the weight of that sits heavy on me today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5c619120-1302-5fd5-8970-ece31c073987', '07e2529e-cd3f-5e47-a7f0-9e8c625ea8a9', 'Living Sacrifice', 'Father, You are Spirit and those who worship You must worship in spirit and truth — I ask You to deepen my worship beyond words to a place of genuine spiritual encounter.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e2f02339-75b8-5779-8a74-3e93d312dbce', '07e2529e-cd3f-5e47-a7f0-9e8c625ea8a9', 'True Worshippers', 'Lord, You seek worshippers who worship in spirit and in truth — not performance, not pretense, but genuine hearts that come to You as You really are.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0575cd1b-d733-50d2-ac0c-68b767629963', '07f3d014-fcb9-54d9-a694-9a93df9dab20', 'Train My Senses', 'Lord, solid food is for the mature, who by constant use have trained themselves to distinguish good from evil — I want to be that kind of person, and I ask You to be my trainer.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3c2a350b-96e8-5ddd-bd6b-b9d080a37846', '07f3d014-fcb9-54d9-a694-9a93df9dab20', 'A Discerning Heart', 'Father, You gave Solomon wisdom and discernment in great measure — You are the same God, and I ask for the same gift, applied to the specific challenges I am facing right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('611c81b9-7952-59e6-9553-dd196af349c3', '09fd582c-0fee-5a23-afd8-35dfc58b9169', 'A Fruit That Must Be Grown', 'Father, self-control is a fruit of the Spirit — which means it is something You grow in me as I stay close to You, not something I produce by willpower alone.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f3756d62-942c-5112-8e12-cfdfa8c1ed2e', '09fd582c-0fee-5a23-afd8-35dfc58b9169', 'Training for Godliness', 'Lord, self-control is trained, not simply given — and I confess I have not always been faithful in the training that builds it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7302a484-e36d-55a0-b2a2-547b52fcb9e9', '0ad19e0f-a16c-5560-956b-91ba153a74b2', 'Anchored in the Storm', 'Father, I will not pretend this is easy — the storm is real, the waves are high, and I have felt the fear rising in my chest.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('fb0bf363-00ab-5a10-b435-f5ee752a61ce', '0ad19e0f-a16c-5560-956b-91ba153a74b2', 'Speak to the Storm in My Life', 'Lord, You stood in a boat in the middle of a raging sea and spoke one word — and it obeyed You. I need that same voice to speak over what is raging in my life right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a7bbeaf5-6eaf-5be8-b477-4199753278c7', '0ce0bc24-8304-5b54-ad3f-44008506cb6e', 'Your Will, Not Mine', 'Lord, I''ve been so busy building my own agenda that I''ve barely stopped to ask You what Yours is.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c688f178-0b86-563e-8df1-734df0d3bad9', '0ce0bc24-8304-5b54-ad3f-44008506cb6e', 'Letting Go', 'Father, I hold so tightly to the life I''ve imagined — the plans I''ve made, the outcomes I''ve demanded, the timeline I''ve decided is right.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('35021ea6-f197-5dea-b263-148223f7770a', '0d5e1f05-11a0-5d22-bc30-49d98ea17f00', 'Life Abundantly', 'Father, I refuse to measure my life by what the enemy has taken — I will measure it by what You have promised to restore, and those are not the same calculation.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('45b2e496-6c96-5bf8-b2a6-e69373970a4d', '0d5e1f05-11a0-5d22-bc30-49d98ea17f00', 'Restore the Years', 'Lord, the enemy comes to steal, to kill, and to destroy — but You came that I might have life, and life in abundance. I choose to stand in what You came to give rather than what the enemy came to take.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7b663170-0f07-5dd6-b0db-1ff26f3be7f4', '0d9c4603-4d10-571e-9a47-3318218a35d2', 'The Integrity of the Hidden Life', 'God, all things are naked and exposed before Your eyes — and I want to live as someone who has made peace with that, not someone hiding from it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('82cec4e9-f2cb-5c4f-b6d7-bef32aad0f99', '0d9c4603-4d10-571e-9a47-3318218a35d2', 'You See What No One Else Sees', 'Lord, nothing is hidden from You — not the thought I entertained this morning, not the thing I do when no one is watching, not the secret appetite I have never named out loud.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('23a21603-8076-5764-b2ef-46d2091ed302', '0ddf5809-bbc2-51ed-b22a-6131b56ee167', 'Make a Way', 'Lord, I ask You to make a door of utterance open to me — for the right words at the right time, delivered to the right people in the right season.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9df652f9-c6a1-5f46-937d-2406cb9643b1', '0ddf5809-bbc2-51ed-b22a-6131b56ee167', 'An Open Door No One Can Shut', 'Father, You are the One who opens doors that no man can shut — I come before You asking for exactly that: open doors for the ministry You have placed in my heart.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6d953285-342c-5eba-a810-1ab6989b6028', '0dfe9a4c-9044-5d7f-b7f2-d03f053013ee', 'Spirit of Adoption', 'Father, I have not received a spirit of fear that makes me a slave again — I have received the Spirit of adoption by which I cry out, "Abba, Father."
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9164b39f-542d-5caa-b50c-8992aa559e8d', '0dfe9a4c-9044-5d7f-b7f2-d03f053013ee', 'Lavished with Love', 'Father, the world does not know what it means to be a child of God — but I am learning, and every time I learn it more deeply it changes how I move through my days.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0e9ffc87-a705-5f2c-9c06-7f0077b61ee3', '0e18dd7a-56ed-5c16-88b9-28b8caf8dee9', 'Ears to Hear', 'Father, Your Word says Your sheep know Your voice — they hear it and they follow. I want to be someone who recognises You when You speak, even in a whisper.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e1c386ac-9327-59f5-b84f-5e7ac0b7b4c6', '0e18dd7a-56ed-5c16-88b9-28b8caf8dee9', 'Tuned to Your Frequency', 'Lord, I do not want to miss what You are saying because I am too busy, too distracted, or too in love with my own plans to stop and listen.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('79319964-74b9-5dc9-bdac-f77e70e1c068', '0ea0aacd-cc57-5d0c-ac42-26ec5730d6b2', 'Royal Priesthood', 'Lord, You call me a chosen people, a royal priesthood, a holy nation, a people belonging to God — I receive that declaration over my life today, even when I do not feel it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f8ad40c4-8a3c-52b2-b890-f08b3521b642', '0ea0aacd-cc57-5d0c-ac42-26ec5730d6b2', 'You Did Not Choose Me, I Chose You', 'Father, Jesus looked at all of humanity and chose me — not because of what I bring to the table, but because of the love that has no explanation beyond itself.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('58e9c1a7-26fb-5cfb-8825-40dfad30be43', '10a39b55-60f9-555e-b2a9-0626ed0acdd4', 'Wounded by Those Who Should Have Protected', 'God, I have been let down by people — people who should have been safe, people I depended on, people who held authority over my life.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a15382ff-27a9-522b-acd8-518e6e6c06c5', '10a39b55-60f9-555e-b2a9-0626ed0acdd4', 'Learning to Trust Again', 'Father, I want to trust people — but I have been burned, and the old openness is harder to come by now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6bb25c5b-6a85-5415-9f41-d5633e86a641', '10a9e15f-cf99-50f3-93b9-2139851589c5', 'A Gift to the Lord of Hosts', 'Lord, Your Word speaks of a people tall and smooth-skinned, feared far and wide, a nation mighty and trampling — brought as a gift to the Lord of Hosts on Mount Zion. That is Africa''s destiny.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('91efd502-f8bb-5142-b26e-a2130386de36', '10a9e15f-cf99-50f3-93b9-2139851589c5', 'A Continent for Your Glory', 'Father, Africa is already the largest and most rapidly growing Christian continent on earth — and I thank You for what You are doing there, even as I ask for so much more.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('33bfe119-bb7e-5554-94cb-3c5dd3f401be', '1146439a-44a5-53df-bb70-89ce8eb832ff', 'In Due Season', 'Lord, fruitlessness is a heavy thing to carry — the sense that nothing is changing, that the labor is not producing, that maybe I misheard or maybe I am not the right person.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ab116336-0c0d-531d-9548-07f423c606e7', '1146439a-44a5-53df-bb70-89ce8eb832ff', 'Apart from You', 'Father, I am honest with You today: I am not seeing the fruit I expected. I have been faithful, I have worked, I have prayed — and the results do not match the effort.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c526c4c2-19e6-5774-b1f6-9571df92d2f1', '1172c5aa-024a-5244-962d-0bbde63e5b3b', 'We Are Not Ignorant', 'Lord, Your Word tells me that I am not unaware of the enemy''s schemes — but I confess that I often am, and I need You to open my eyes to what is really happening around me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cb24527a-b496-54dd-b338-d0e8ab964469', '1172c5aa-024a-5244-962d-0bbde63e5b3b', 'Outwitted by Grace', 'Father, I will not give the enemy more attention than he deserves — my eyes are on You, because where my gaze goes, my faith follows.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1034e46d-f3cb-5d6b-ac93-e91def57ebc6', '122e5896-619b-58a8-b0f2-9eec82aad2d5', 'When Home Doesn''t Feel Like Peace', 'Father, I will be honest — home has not always felt like peace, and I bring that reality to You without dressing it up.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9b0e7f8e-2ae3-50a7-9bf8-9bd1e1115202', '122e5896-619b-58a8-b0f2-9eec82aad2d5', 'Let Shalom Dwell Here', 'Lord, I pray for the place I call home — that it would be a place of peace, not tension; security, not fear; love, not strife.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cd49528a-b224-5570-9fb1-823d235ae726', '1389f742-9bed-5353-b55b-3f660c60e653', 'This Has Gone on Too Long', 'Lord, I am not just someone who gets angry sometimes — anger has become a default, a first response, a way of moving through the world.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f1d14080-c52f-5c69-99ec-95c67d1f1eec', '1389f742-9bed-5353-b55b-3f660c60e653', 'Do Not Make Friends with Anger', 'Father, Your Word warns me not to make friends with an angry person, not to associate with one easily provoked — I wonder sometimes if I am that person.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('627228d4-47a5-5f0b-889b-1d2e1ce7f948', '1502f3a7-cfc3-5572-8873-c42cef6f039f', 'Covered by the Blood', 'Lord Jesus, I thank You for the blood You shed on Calvary — not as a symbol, but as the actual, powerful, eternal substance that purchased my redemption and my freedom.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d0cb12c8-6fb6-51a2-a371-64a74071b20a', '1502f3a7-cfc3-5572-8873-c42cef6f039f', 'The Word of My Testimony', 'Father, I come boldly to Your throne of grace through the blood of Jesus — the veil is torn, the way is open, and I have access that the enemy cannot take from me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9f8d4c5c-5617-5efb-bffc-6fc67811de43', '151c1bc8-f160-5eac-8f2e-4b62a2394600', 'Blessed Are the Peacemakers', 'Lord, You called peacemakers blessed and called them sons of God — I want to be someone who carries that identity into every room I enter.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f1063254-45fa-5cb2-86a8-a7669091ad01', '151c1bc8-f160-5eac-8f2e-4b62a2394600', 'The Hard Work of Making Peace', 'Father, there is a situation in my life right now where peace needs to be made — and I am aware that making it will require something of me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0328bb68-4275-5bf3-9812-d1c6de402419', '180673ab-489a-5cdb-8caa-56966283deff', 'All Things Work Together', 'Lord, You cause all things to work together for good for those who love You and are called according to Your purpose — I am called, and I trust that even the detours have purpose.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f49aafc9-2aeb-5bdd-a7f2-a09974757e0a', '180673ab-489a-5cdb-8caa-56966283deff', 'Your Purpose Will Stand', 'Father, Your purpose for me cannot be stolen, cannot be derailed by my failures, cannot be outdated by my age or limited by my circumstances — it stands, because You stand.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('25e48273-ade0-562d-9d08-10595ab9ae5d', '1870c0ed-81db-5642-afb8-ba5a8258fcce', 'You Will Not Let Me Wither', 'Lord, in the hard seasons it is easy to believe the drought is permanent — help me to see what You are doing even when I cannot feel it, and to trust Your work underground.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8a35a299-4703-5387-bef3-1dd5f5346dec', '1870c0ed-81db-5642-afb8-ba5a8258fcce', 'Green in the Desert', 'Father, Jeremiah''s vision is the cry of my heart today: to be like a tree planted by the water that does not fear when heat comes — whose leaves stay green even in drought.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3fcc343b-9954-5750-a46e-4a9df1b28958', '1874d53e-1923-53b7-961b-121a33dcf6da', 'Faithful to What I Have Been Given', 'Lord, the gifts and calling You have placed on my life are without repentance — they do not expire, they do not change when my circumstances change, and I will not treat them as optional.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('fefcc86e-e529-579f-812e-9f9a6c64b62a', '1874d53e-1923-53b7-961b-121a33dcf6da', 'Before I Was Formed', 'Father, before I was born You set me apart — not because of anything I had done, but because You are a God of purpose who calls from before the foundation.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('26ff6cfe-d11f-550a-8847-a2d3c300004f', '1af342fb-5607-54e9-a967-9c7ec41d90a5', 'A Home Set Apart', 'Father, I ask that You would sanctify this home — that it would be a place marked by prayer, by Scripture, by love that goes beyond what is natural.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d9dfada8-49d1-5523-bea6-adb92067693a', '1af342fb-5607-54e9-a967-9c7ec41d90a5', 'Unless the Lord Builds', 'Lord, I declare with my whole heart: as for me and my house, we will serve the Lord — let that be more than a banner on our wall, let it be the rhythm of how we actually live.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3bfc90de-de24-57e6-b0c9-5f8badc330e5', '1decbc61-da03-5271-b981-71194b424585', 'Pour Out Your Spirit', 'Father, show us Your unfailing love and grant us Your salvation — show us, not as a concept but as a manifest presence, as a felt and seen and undeniable reality.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dcf76977-cda9-5e9c-9148-49575c3bc872', '1decbc61-da03-5271-b981-71194b424585', 'Do It Again', 'Lord, I have heard of Your fame. I stand in awe of Your deeds. What You did in the past — the Great Awakening, the Welsh Revival, the Azusa Street outpouring — renew those deeds in our day.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('561f0081-e42f-51d1-99b7-e87882bba303', '2056f55d-06f3-531f-8be4-adc3278ae204', 'Known by This', 'Lord Jesus, You said the world would know Your disciples by our love for one another — I want that to be true of me in a way that can actually be seen.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('aa545573-dc3c-53c7-9e9a-18d8f5ec83df', '2056f55d-06f3-531f-8be4-adc3278ae204', 'Love That the World Can See', 'Father, I want to be a person who is genuinely known for love — not as a personality type, not as a strategy — but as the visible evidence of You living in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3b340006-1319-535e-ac85-cd9a087a829c', '230869c0-59bc-5c6b-8e3f-5a761aa5d247', 'Forget the Former Things', 'Father, You said do not dwell on the past — see, I am doing a new thing — and I confess that I have sometimes lived more in what was than in what You are doing now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5f0d45f1-03ce-50e4-8931-b6422f6eb186', '230869c0-59bc-5c6b-8e3f-5a761aa5d247', 'Held in Every Chapter', 'Lord, every memory I carry — the painful ones, the shameful ones, the ones that still make me flinch — every single one of them was held in Your sovereign hand as it happened.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c3d07d39-c785-51b3-9f5b-bd60ad1cfe81', '240cdf72-f071-51ef-8606-aaf052086bc1', 'Blessed Be Egypt My People', 'Lord, You said Egypt shall be My people, Assyria My handiwork, and Israel My inheritance — three historic enemies, called together as a blessing in the midst of the earth. That is Your heart for the Middle East.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d1a3966c-0511-5587-ad7e-4c50e34361a6', '240cdf72-f071-51ef-8606-aaf052086bc1', 'Until All Israel Is Saved', 'Father, Your covenant with Israel is irrevocable — and I stand in agreement with Your purposes for the Jewish people, for the land, and for the extraordinary eschatological plan You are unfolding.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('22db96ac-1e8a-514f-abbc-def5e382b186', '25f0869e-ea78-5fdc-9c4d-8b7f2bf10232', 'Marked by the Struggle', 'Father, faith has not always been easy for me — there have been seasons of real struggle, real doubt, real darkness — and I am not ashamed of that anymore.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2d9c2a77-51d4-5900-8a65-83bdfc06aee0', '25f0869e-ea78-5fdc-9c4d-8b7f2bf10232', 'I Will Not Let You Go', 'God, I am wrestling with You — not to fight You, but because I need something from You that I have not yet received, and I am not willing to walk away empty.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('35487727-f313-531e-9c36-50fed88e5010', '26d17965-9832-5f81-b8ef-3c05c67a19b7', 'The Gift of Those Who Know Me', 'Father, thank You for the people You have placed in my life — for family who have known me longest and friends who have chosen to stay.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8a6e47bc-45c8-58f9-a3e4-2408ad912687', '26d17965-9832-5f81-b8ef-3c05c67a19b7', 'Woven Together by Your Hand', 'God, You set the lonely in families — You are the one who knits people together, and the people I love most were placed in my life by design, not accident.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7053fac6-47bb-5b3a-a19c-3ece880714d4', '2818c953-19b7-529b-a189-73976d47fba1', 'Choosing What Does Not Come Naturally', 'Father, I am praying for [name], for the one who wounded me — and I want You to know it is not easy, but I am choosing it because You asked me to and I trust that You know what You are doing.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8a59351d-5ba3-514a-b53e-5e8659a2473b', '2818c953-19b7-529b-a189-73976d47fba1', 'The Command I Resist', 'God, this is the command that undoes me — love your enemies, pray for those who persecute you — and I am honest enough to say that I have not done it well.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('311329fa-ec03-5234-8c0f-d9b72c823112', '29795cd4-b96d-59cc-ba3e-6c3114c0d346', 'Remember Those in Chains', 'Father, even as I pray in safety and freedom, I know that today my brothers and sisters in other parts of the world are suffering because of the name of Jesus — and I will not forget them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ca3db47b-1e04-5b9d-bd28-8de1638e5d4f', '29795cd4-b96d-59cc-ba3e-6c3114c0d346', 'Their Faith, Our Fuel', 'Father, I am humbled and shamed into deeper faith when I consider those who have lost everything to follow You — and still they refuse to turn back.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('33a495b2-3fa1-57cb-bb83-c3dc101da1a6', '2a60aaf8-c316-591f-b53d-38d9a8885038', 'Set Free Inside', 'Father, emotional pain is real pain — and I refuse to minimise what I am carrying or pretend that strength means not feeling it. I bring it all to You, honestly and without performance.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('90ca1529-8500-5453-94b3-bc7f765ea0e1', '2a60aaf8-c316-591f-b53d-38d9a8885038', 'Close to the Brokenhearted', 'Lord, You are close to the brokenhearted and You save those who are crushed in spirit — I am bringing You the places inside me that have been crushed, and I need You close.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3981e566-f621-5652-8d0d-8c5ae624139f', '2b864121-dff7-55c1-af75-0fa06e526e36', 'The Lord Who Heals', 'Lord, I bring my body to You — the symptoms I am watching, the fears I have googled, the worry that lives just beneath the surface about my health.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('95d7beb0-b6a8-566f-8d49-fb6df02c872a', '2b864121-dff7-55c1-af75-0fa06e526e36', 'When My Body Feels like the Enemy', 'God, my relationship with my body has been marked by fear — fear of what might be wrong, fear of what I might lose, fear of pain, fear of decline.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('011bd8a6-dc96-50d6-bef4-6ea9584ccba4', '2dcd9d3c-ff27-5909-bb19-d875942d8f46', 'The Back to Jerusalem Vision', 'Father, the church in Asia — particularly in China — has carried a vision to take the gospel back along the Silk Road to Jerusalem, through the most unreached places on earth. I pray for that vision.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d752a768-c76a-5c68-983e-05187f1e1b70', '2dcd9d3c-ff27-5909-bb19-d875942d8f46', 'Every Nation, Tribe, and Tongue', 'Lord, I saw in Your Word a great multitude that no one could count, from every nation, tribe, people, and language, standing before the throne — and Asia must be fully represented in that crowd.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2f712c1f-d20d-5c9d-a78a-caf8bd673193', '2f8ca52d-8ca0-56c1-a530-b0ec67162d60', 'A Strong Tower', 'Lord, Your name is a strong tower and the righteous run into it and are safe — I run into Your name today and I declare it over everything that threatens me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('97162b2f-6dea-5a42-aa4e-5fd04ea791da', '2f8ca52d-8ca0-56c1-a530-b0ec67162d60', 'How Majestic Is Your Name', 'Father, every name You carry is a window into who You are — and the more I know Your names, the more I know You, and the more I know You, the more I worship.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('578a4b7d-217c-506b-afcb-2e85d8cf5983', '30028e06-5029-5e32-8fa2-62b0f406aa7b', 'The Desire You Placed in Me', 'Father, You know the desire I carry — the longing for a partner, for covenant love, for someone to walk this life beside me — and I bring it openly to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5d528b06-e69f-531c-9f6d-c7f78118e579', '30028e06-5029-5e32-8fa2-62b0f406aa7b', 'While I Wait', 'Lord, waiting is not passive — I choose to trust You actively in this season, believing that Your plan for my life is good and Your timing is perfect.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b11bef1b-f5c0-50f7-a8d7-e10e9d32a7b5', '30572a9d-6169-58c0-a0e5-b61cd0b17411', 'One Flesh, One Heart', 'Lord, You said the two shall become one — I ask You today to do the deeper work of making us truly one: in spirit, in purpose, and in love.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d33e2f37-f95c-5f8c-b3a1-51aa3294999f', '30572a9d-6169-58c0-a0e5-b61cd0b17411', 'Draw Us Close', 'Father, You designed marriage and You designed intimacy — You are the author of the love between a husband and a wife, and I come to You about ours.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1dfac731-364f-58d5-8c6b-c91cf6746419', '312ddab9-427b-50c4-91bc-732ce9f33f33', 'Before I Open My Mouth', 'Lord, I have a hard conversation ahead of me, and before I say a single word I need to come to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b751c306-9dde-52b3-aea4-5453e313ba6c', '312ddab9-427b-50c4-91bc-732ce9f33f33', 'Speaking Truth with Love', 'Father, I have been putting off a necessary conversation because I am afraid of how it might go — afraid of conflict, of being misunderstood, of making things worse.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5c87fbc2-9331-5489-ae99-dd55b3988fd2', '33aef114-cea6-5d5c-9e3d-48df2600f500', 'A Renewed Mind', 'Father, I refuse to be conformed to the patterns of this world — I ask for the renewing of my mind, daily, word by word, truth replacing lie, light replacing shadow.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('97cd5859-09d4-5ae0-b825-2658d35d7904', '33aef114-cea6-5d5c-9e3d-48df2600f500', 'Every Thought Captive', 'Lord, the battlefield of the mind is where so much of the spiritual war is won or lost — and I confess I have not always been a good gatekeeper of what I allow in.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('db735b02-af30-520c-9f96-bd3e865ca3b0', '33c8afe3-13a9-5a9e-a130-60e98b38bc14', 'Letting Yourself Be Carried', 'Father, I struggle to receive — to receive help, to receive care, to let people see me in need without immediately redirecting attention away from it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e8dbc775-9add-5d7a-8e6c-d2e6be06d648', '33c8afe3-13a9-5a9e-a130-60e98b38bc14', 'I Don''t Have to Do This Alone', 'God, I have made an idol out of self-reliance — and I''ve dressed it up as strength, as independence, as not being a burden to anyone.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e7eb324f-5fd4-532c-8b13-d210b9ebe468', '343fc72d-80d3-5789-b8a5-edb50ddb4b41', 'A Wise Steward', 'Lord, money is a tool and You are the Owner — help me to hold everything I have loosely, knowing I am a manager of Your resources and not an owner of my own.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ff231259-c7fb-51c7-9c31-25f4daa4cf88', '343fc72d-80d3-5789-b8a5-edb50ddb4b41', 'Bring the Whole Tithe', 'Father, You said to bring the whole tithe into the storehouse and test You in it — that You would open the floodgates of heaven and pour out blessing without room enough to contain it. I take You at Your Word.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3fe5cd4f-7176-5e72-9caf-99516b8b81cc', '34b2f36f-9422-5549-b3e0-1869fed5ad44', 'When Love Is All That Remains', 'Father, prophecy will pass away, tongues will cease, knowledge will pass away — but love never fails — let that truth reorder what I invest my life in.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('895f0a3c-6a15-582a-a1e1-e45a1f97112d', '34b2f36f-9422-5549-b3e0-1869fed5ad44', 'Your Love Does Not Quit', 'Lord, I have been loved by people who eventually ran out of love — who withdrew, who left, who could not sustain it — and I have learned to brace for that, even from You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('635ff157-1f90-5a1d-8a55-8f9bf256336d', '3800d71d-38ae-5840-a2b9-21e7eba47d01', 'I Need to Say This to You', 'God, I am angry at You — and I almost didn''t say it, but I know You already know, and hiding it from You has only made it worse.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d56ed307-f7b3-5c48-b2af-1db9177b1458', '3800d71d-38ae-5840-a2b9-21e7eba47d01', 'Wrestling with You', 'Lord, if I''m honest, there are questions underneath my anger that feel too big and too raw to speak out loud — but I am going to try.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4317ceb1-890b-5698-91dd-2d0c72f0e513', '3828eb21-a67a-5b0d-a64c-1721926e890f', 'This Body, This Breath', 'Lord, I am fearfully and wonderfully made — and I confess I often take that for granted, treating as ordinary what is actually extraordinary grace.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6924c0bc-64cb-51c7-a1fa-4275720473e4', '3828eb21-a67a-5b0d-a64c-1721926e890f', 'Strength Renewed', 'Father, You give power to the faint and increase strength to those who have none — and I come to You today as one who needs exactly that.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1e001b5c-17a4-52c5-bad3-b03058bf664b', '384e791c-bb01-50fa-a619-97ceebca2f8e', 'What God Has Joined', 'Father, I take seriously the warning of Your Word — the enemy walks about like a roaring lion, and my marriage is a target worth protecting.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('73573d46-f3e2-56a5-8ea3-1f76c96504b1', '384e791c-bb01-50fa-a619-97ceebca2f8e', 'A Wall of Fire Around Us', 'Lord, I am not naive — the enemy hates covenant, and our marriage is a covenant worth attacking. Today I choose to fight for it in prayer.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('726aa141-ba21-5d21-959a-372ad7c059a8', '3897f63b-2b7a-5349-80f4-50fed0b1bfa8', 'You Love Me Still', 'God, I find it easier to believe in Your love in theory than to feel it as mine — to know it as a doctrine rather than a daily reality — help me to cross the distance between knowing and receiving.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('91ea38bf-2775-500e-aa41-440b3fd01cda', '3897f63b-2b7a-5349-80f4-50fed0b1bfa8', 'Loved Without Condition', 'Father, I want to receive what I so often acknowledge only in my head — that You love me, not as a concept, but as a reality that is meant to reach the deep places in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6102d129-084f-5659-83b7-eb3e67a5420f', '38d2f056-30e6-57ee-b219-2e864df30858', 'Holy Anger in an Unjust World', 'Father, there is so much in this world that should make me angry — injustice, suffering, exploitation of the vulnerable — and I don''t want to grow numb to it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e30f2f0c-a99e-56dc-85ce-987549db5d18', '38d2f056-30e6-57ee-b219-2e864df30858', 'Moved by What Moves You', 'God, You hate evil — not casually, not politely, but with the full weight of Your holiness — and I want my heart to be shaped by Yours.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('060fc23e-0ad6-5be2-936e-95a8ae77d7ef', '39a5f54d-0e1e-54b8-8f3b-09f912faa049', 'Eager for Your Gifts', 'Father, Your Word tells me to eagerly desire spiritual gifts — so I come before You not timidly but with expectation, trusting that You delight to give them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b6ab3683-2a17-5682-96ca-397bf3350c03', '39a5f54d-0e1e-54b8-8f3b-09f912faa049', 'Useful in Your Hands', 'Lord, I recognise that spiritual gifts are not trophies — they are tools. I ask You to give me not what feeds my pride, but what serves Your people.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3bada69a-6736-5675-816e-725724ed35c6', '3aeb8ba1-a58b-563d-bc6b-d10402133a74', 'You Have Overcome', 'Jesus, You were tempted in every way that I am tempted, and yet You did not sin — that means You understand what I am facing right now, and You can help.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d0d8fb4e-cd52-5af7-a53b-535c9384a26d', '3aeb8ba1-a58b-563d-bc6b-d10402133a74', 'A Way of Escape', 'Lord, Your Word promises that no temptation has seized me that is not common to everyone — and that You always provide a way out. I need to see that way today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f048b350-68d7-5411-83c8-866eaee2350d', '3bb3b8d2-8025-5fff-9e8e-2a02abe0875d', 'Enter His Gates', 'Lord, I enter Your gates with thanksgiving and Your courts with praise — not because everything is perfect but because You are good and Your mercy endures forever.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f74ed782-3208-5964-9a97-921a2012e1a9', '3bb3b8d2-8025-5fff-9e8e-2a02abe0875d', 'Bless the Lord, O My Soul', 'Bless the Lord, O my soul — and all that is within me, bless His holy name — I want every part of me to participate in this gratitude, not just my words but my will, my memory, my whole self.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b71e714b-7967-590e-888f-1bcef799d84a', '3c0a2f58-0207-5de4-948c-f94f242401bb', 'He Reveals Deep and Hidden Things', 'Father, Daniel blessed You as the God who reveals deep and hidden things — and I come to You today as the same God who has not changed, who still reveals to those who seek.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d5d3d58d-85f7-533f-9da2-dfad5b57eca0', '3c0a2f58-0207-5de4-948c-f94f242401bb', 'Open the Eyes of My Heart', 'Lord, I ask for the Spirit of wisdom and revelation so that I may know You better — not just know more about You, but know You, deeply and truly, the way a person knows someone they love.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('10c5b91b-2475-59c1-a761-5ccd03bd5f79', '3de36e13-2f92-5c85-ad56-f84aef35bb11', 'Hidden in My Heart', 'Father, I want Your Word hidden in my heart — not stored in a drawer or confined to one hour on Sunday, but living in me and shaping how I think, respond, and love.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f79b46f5-2f0f-5e32-8100-05284ce804ed', '3de36e13-2f92-5c85-ad56-f84aef35bb11', 'Your Word, My Life', 'Lord, Your Word is a lamp to my feet and a light to my path — in a world full of noise and confusion, You have given me something steady, sure, and unchanging.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('49c9a38f-1556-5154-9a1a-9b144a6fc406', '3effc646-6084-580f-bac0-d074072905eb', 'Confidence That Points to You', 'Father, I can hold myself together so well that I forget how much I need You — and that self-possession has been mistaken for faith, by others and sometimes by me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('528919c7-4d8b-5c73-89e9-db2d522adbc4', '3effc646-6084-580f-bac0-d074072905eb', 'Knowing the Difference', 'God, let not the wise boast in their wisdom, the strong in their strength, or the rich in their riches — but let them boast in knowing You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3bc05c72-0438-5e27-8eb7-70ec4ae55c46', '3f2154b0-69ec-5281-aa66-1bbd94353063', 'Seasoned with Salt', 'Father, be wise in the way you act toward outsiders — make the most of every opportunity — I want to live that way, as someone who moves through the world with intentionality and grace.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a8f09dd4-6521-5cb7-ba10-de1df827252d', '3f2154b0-69ec-5281-aa66-1bbd94353063', 'Walk with the Wise', 'Lord, the one who walks with the wise grows wise — I want to be intentional about who I walk closely with, and I ask You to bring wise people into my life and give me the humility to learn from them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0715d467-4aa3-5089-b330-e5c2d9fdd4db', '41a4c9e4-f7d8-51cf-8563-29fd69f2f624', 'Clothed with Power', 'Father, before the disciples did anything, You told them to wait — wait for the power of the Holy Spirit to come upon them. I need that same power today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('09e713e7-2a71-57d7-9ad1-c6f2aa005fca', '41a4c9e4-f7d8-51cf-8563-29fd69f2f624', 'Not by Might', 'Lord, You promised that when the Holy Spirit comes upon us, we will receive power — not talent, not strategy, not confidence in ourselves, but genuine supernatural power.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ac92e6d1-8a06-5c5a-bea7-7953445e3d5a', '41e39865-2c3b-57f2-94a3-000066a735b2', 'The God of Abraham Is My God', 'Lord, the same God who called Abraham out of Ur, who made covenant with him, who fulfilled every promise He spoke — that God is my God, and His covenant covers me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e8588f38-1fd6-52ce-9aa7-cbda7b5a986a', '41e39865-2c3b-57f2-94a3-000066a735b2', 'Heir of the Promise', 'Father, Your Word declares that through Christ the blessing of Abraham has come to the Gentiles — and by faith, that blessing belongs to me. I receive it today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('04e012e1-158f-56dc-8876-a3b33636adea', '429c4049-eb5f-5621-9a61-35b275e317c9', 'God Is Our Refuge', 'Lord, You are a very present help in trouble — not a distant helper, not a slow responder, but an ever-present refuge — and I run into that refuge today with everything I am carrying.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('63bf30f8-2142-5612-80d8-50cd0938216f', '429c4049-eb5f-5621-9a61-35b275e317c9', 'From Survival to Life', 'Father, trauma taught my body to survive — and survival has served me — but You are calling me beyond survival into the fullness of life that Jesus said He came to give.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8d8d5623-acd2-5b37-bf76-1d3a72c935f3', '429cb69d-255e-57cd-9e56-72f4694c3c7b', 'In the Morning, Lord', 'Lord, in the morning You hear my voice — before the noise of the day, before the demands, before the worries, I bring my worship to You first.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f0481e22-e2e9-5cd8-ba47-e3f07d71369b', '429cb69d-255e-57cd-9e56-72f4694c3c7b', 'Before the Day Begins', 'Father, morning by morning You give me new mercy — and morning by morning I want to meet You here, in the quiet, before anything else has my attention.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c067447d-b7d1-5234-97ca-5b2dcecf5961', '435e2f69-bc1f-552c-871e-69d19f6af832', 'Overflow for Those Around Me', 'Lord, I am bringing others before You today — people in my life who are struggling to hope — and I am asking You to do for them what only You can do.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d63d9a74-aa71-56b4-9df4-e502fc96eed4', '435e2f69-bc1f-552c-871e-69d19f6af832', 'Interceding for the Hopeless', 'Father, there are people in my world who do not have hope right now — who cannot see a way forward — and I am bringing their names and their need to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ad2e4e85-88ce-56a5-bdd4-c1a30e7b3def', '44364d46-b8e0-505a-87ff-93cbc8acb4bc', 'Thanksgiving Is the Door', 'Lord, I enter Your gates with thanksgiving and Your courts with praise — gratitude is not just a feeling, it is the way I step into Your presence.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bc76c619-f27c-5c67-b101-e832250f6a29', '44364d46-b8e0-505a-87ff-93cbc8acb4bc', 'Draw Near with Confidence', 'Father, the invitation to enter Your presence is one I never want to stop responding to — every day, every moment, the way is open because of Jesus.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('78e0da38-d9ce-5346-9518-1d9c192eb027', '44a76b01-c385-5484-87a6-f701e4736e96', 'Lord, Save Them', 'Lord, I bring before You the people in my life who do not yet know You — the ones who seem far, the ones who seem close but have never crossed the line of faith, the ones I have given up praying for.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8c78ff78-6d32-5bbe-b3bd-cc2ab4656bde', '44a76b01-c385-5484-87a6-f701e4736e96', 'A Heart for the Harvest', 'Father, my heart''s desire and prayer for those around me who do not know You is that they would be saved — and I ask You to make that desire more than a sentiment, but a burden that drives me to pray.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2bd90fda-2c58-5022-ad40-9e06d30538c5', '44b43d35-9b58-5a93-9f2b-9e346e4c06a4', 'Releasing What I Carried', 'Father, I am grieving a future that never came — a door that stayed closed, a prayer that went differently than I had hoped — and I did not know how much it would hurt.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d7307797-67ce-55a0-a127-eea9891443cf', '44b43d35-9b58-5a93-9f2b-9e346e4c06a4', 'Standing in the Valley of Dry Bones', 'Lord, the thing I hoped for has not come — the dream I carried for years has gone quiet — and I am standing in a valley of dry bones wondering if anything can live again.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6404aefa-dfc2-5aa8-9386-8f4dd89e19cf', '44f6c001-71ae-5b19-b1da-51c012209e04', 'It Was Never Mine to Take Credit For', 'Lord, I have been tempted to say in my heart: my power and the strength of my hand have produced this — and I know that thought is both wrong and dangerous.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('72fbb966-3b72-58c9-a3f7-57f22db79b8b', '44f6c001-71ae-5b19-b1da-51c012209e04', 'After the Win', 'Father, something went well — and I am bringing that to You before I take more credit than I deserve.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6113de85-0f20-5ed3-b664-cbd442e72129', '461d24ce-32ac-52e5-a9f6-6ec77ef9b0b1', 'The Lord Rebuke You', 'Lord, Your Word warns me to be sober and alert — the enemy prowls like a roaring lion, looking for someone to devour, and I refuse to be caught off guard.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dbe57174-cebd-5844-9db0-84a95bcbd452', '461d24ce-32ac-52e5-a9f6-6ec77ef9b0b1', 'Steadfast and Immovable', 'Father, the enemy''s roar is designed to produce fear — but You have not given me a spirit of fear, and I will not give the lion the response he is looking for.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0bc8049b-3e8a-52c7-abcb-8c706d20eb74', '47c38acb-5853-56d0-8666-003c4509a028', 'The Cross Changes Everything', 'Father, the cross is not just my salvation, it is my identity — and when I boast in anything else I am saying the cross wasn''t enough.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('41ae2c13-8590-5f85-871d-6f5d2f8b6ad0', '47c38acb-5853-56d0-8666-003c4509a028', 'There Is Only One Thing Worth Boasting In', 'Lord, may I never boast except in the cross of our Lord Jesus Christ — that is Paul''s declaration, and I want to make it mine today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0188cf87-bbd2-5984-b0fc-62b332d27812', '4894e476-5eb6-5aca-95be-9dff381b04d4', 'Christ Lives in Me', 'Father, the approval I have been searching for in so many places has already been given — You have accepted me in the Beloved, and that acceptance does not come and go.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4bccb27c-6506-5abd-a374-826692decc6f', '4894e476-5eb6-5aca-95be-9dff381b04d4', 'Chosen in Him', 'Father, You chose me in Christ before the creation of the world to be holy and blameless in Your sight — my identity was settled before I ever drew my first breath.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('22067a85-865a-5216-9c07-804c64abefb9', '48a257dc-ef1b-54c8-8238-e513a9d1eb65', 'I Call from the Depths', 'Lord, I am in the pit — I am not speaking metaphorically — I am in a darkness that feels like it has walls, and I am calling to You from the bottom of it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e2632ff6-d9a9-5989-b398-5c49822965e4', '48a257dc-ef1b-54c8-8238-e513a9d1eb65', 'When the Dark Won''t Lift', 'God, I have cried to You day and night — I have brought this darkness before You over and over — and I am exhausted in a way that sleep does not fix.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('460cc3d0-25ec-56c3-9631-f7de638d9ece', '49a361b6-78e5-590d-adb3-f128ad872a2a', 'Living a Life Worth Passing On', 'Father, I am thinking today of those who come after me — the children, the young people, those who are watching — and I want my life to be something worth inheriting.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4b2e91ac-2ed6-516d-9967-892ca1444ca4', '49a361b6-78e5-590d-adb3-f128ad872a2a', 'A Heritage of Hope', 'Lord, I want to be someone who passes faith forward — who does not keep what You have done for me private — who tells the stories so that the next generation has something to stand on.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8c9db10e-426d-5bf2-a411-bb1586d4b417', '4adde81e-10f3-58e2-8532-fd3332eb1fd1', 'Built Together', 'Lord, I love Your church. She is imperfect and sometimes difficult and often disappointing — and she is the body of Your Son, and I will not give up on her.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('db45afcf-3c23-509e-9bef-c3acd063bc76', '4adde81e-10f3-58e2-8532-fd3332eb1fd1', 'A Church Made Glorious', 'Father, I pray for the church — not just my local congregation, but the whole body of Christ across the world — that she would be strengthened with power through Your Spirit in her inner being.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7f618e31-fdb6-5f15-b721-91f7374a1ff0', '4af1009d-9745-5f34-ba30-8e11b1788f31', 'Releasing Money''s Hold', 'God, I will be honest — money has a power over my peace that it shouldn''t have, and I want to bring that to You today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bb405b18-b520-50f7-be0c-5584ab59af38', '4af1009d-9745-5f34-ba30-8e11b1788f31', 'When the Numbers Are Frightening', 'Father, the numbers in front of me right now are frightening — and I have spent too many nights losing sleep over them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6c5da575-840b-5fb6-a2df-141e87365370', '4b5a310b-1656-54d1-b57d-9c9eb9eaed62', 'The Fields Are White', 'Lord, You told Your disciples to lift up their eyes and look at the fields — they are white for harvest, already ripe, ready now — and I choose to look today with eyes of faith, not of discouragement.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e299a323-30bf-5601-88aa-ea57729ea180', '4b5a310b-1656-54d1-b57d-9c9eb9eaed62', 'Lord of the Harvest', 'Father, You are the Lord of the harvest — which means the harvest is Yours, the timing is Yours, and the strategy is Yours. I come to You first, asking You to direct the work.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6687ae60-4270-5360-a224-82e9df6c5ec0', '4c1b2bd4-7762-5981-8f6f-134befd602c7', 'Renewing Strength in the Wait', 'Lord, I am waiting — and the waiting is the hard part — and I am asking You to meet me in it rather than just rushing me through it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ccb7a413-ab8f-5af0-91a3-6bf7831b867c', '4c1b2bd4-7762-5981-8f6f-134befd602c7', 'The Discipline of Waiting', 'God, waiting does not come naturally to me — I want resolution, I want movement, I want an answer — and You are asking me to be still, and it is harder than it sounds.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('becac793-9654-50e0-83d6-71d9e8751c3e', '4da992d3-b3b3-57a3-afbd-8ec82d891050', 'Trusting the One Who Sees the Whole', 'God, there are things happening in my life right now that I cannot explain — and if I''m honest, they have shaken me more than I want to admit.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f6368875-fa89-5d3c-aaf9-cc023d95f7b6', '4da992d3-b3b3-57a3-afbd-8ec82d891050', 'When the Pieces Don''t Fit', 'Lord, I confess that I have been trying to make sense of something that is beyond me — and the not-knowing has left me exhausted and afraid.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('11c87935-e50c-547f-901b-6b58dd8f7f91', '4eccb9e0-2f3a-5b9d-90bf-d18f019a187c', 'I Have Been Starving Myself', 'Lord, I confess that I have known the Word is where I find You, and I have still found reasons not to go there — busyness, fatigue, distraction, and sometimes just the quiet preference for other things.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('456141f2-1e0a-5b3b-b26a-f3e80d9fb030', '4eccb9e0-2f3a-5b9d-90bf-d18f019a187c', 'Bread I Have Not Eaten', 'Father, Your Word tells me that people do not live by bread alone but by every word that comes from Your mouth — and I confess that I have been trying to live without the bread You have provided.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('54e8ad0b-66b6-56e8-a6d7-1d43ef8c2138', '505e318e-0931-5133-83f2-8048db48fd7c', 'I Have Called You by Name', 'Lord, You have called me by name — not by the name my failures gave me, not by the name my critics gave me, but by the name You have always known me by.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b2b4c0d5-3af3-5993-b2b1-956ce0adde41', '505e318e-0931-5133-83f2-8048db48fd7c', 'He Rejoices Over You', 'Father, You rejoice over me with singing — that is hard to receive but I choose to receive it, because You said it, and You do not say things that are not true.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('13d51312-1056-52be-9d18-df025b6d65e7', '507337a0-3602-57be-8d35-27007776e9a8', 'Love without Compromise', 'God, I want to love people well — and I also want to stay close to You — help me to hold both without using one as an excuse to sacrifice the other.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('821e42ea-1be2-52a6-b9d4-cee5efcba9f8', '507337a0-3602-57be-8d35-27007776e9a8', 'Walking with the Wise', 'Lord, some of the temptation I face does not come from within me alone — it comes through people I spend time with, environments they bring me into, expectations they carry about who I should be.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('47656915-16eb-59c8-bc66-57c4e9bf5550', '50c9dcac-8971-5906-950f-afc83ad3273c', 'I Will Not Keep Silent', 'Lord, watchmen pray until breakthrough comes — not until they are tired, not until others stop, but until You act. Give me that tenacity in intercession.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d6918f32-6527-5c07-b3e2-1ab0832dfb72', '50c9dcac-8971-5906-950f-afc83ad3273c', 'Set Me on the Wall', 'Father, You said You have made Your servants watchmen over Your people — I accept that commission today and I ask You to teach me what it means to take my place on the wall.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3082539d-fc91-5ed6-8a0b-5a79f10b9e21', '5551e0a1-26c2-5653-b601-d6d7f6a139da', 'I Cannot Do This Without You', 'God, You said it plainly: apart from You I can do nothing — not manage it, not achieve it, not sustain it, not produce anything of lasting worth.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b4fa2e1d-b8f1-5443-8119-4576f0b3fe24', '5551e0a1-26c2-5653-b601-d6d7f6a139da', 'Strong in My Weakness', 'Father, Paul boasted in his weaknesses so that Christ''s power would rest on him — and I want to learn that kind of counterintuitive surrender.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1b958b28-e840-5521-81f8-94c656d08d17', '5566e2b2-d9d9-5878-abd0-348bdfe9f4fc', 'My Whole Heart', 'Lord, You are worthy of my whole heart — not the leftover portion, not the hours that aren''t already claimed — my whole heart, my whole soul, my whole mind, my whole strength.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6f8f044c-95ff-5a08-b752-28df1896ed5b', '5566e2b2-d9d9-5878-abd0-348bdfe9f4fc', 'Reordering My Loves', 'Father, I want my love for You to be more than a Sunday sentiment — I want it to be the organising principle of my life, the thing that shapes every decision and every desire.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6577c041-8ba3-5d9d-a5f0-4d2bbfd2906f', '55e7bdd0-5102-5256-b753-fb723d2bb669', 'Come, Holy Spirit', 'Father, thank You that You did not leave us as orphans — You sent the Holy Spirit to be with us and to live within us, closer than any friend we have ever known.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d902f999-1c3d-5dd0-bc1c-c75d9807f904', '55e7bdd0-5102-5256-b753-fb723d2bb669', 'A Dwelling Place for Your Spirit', 'Lord, I confess that I have sometimes lived as though I were alone — striving, anxious, relying on my own strength as if the Spirit within me were not real.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('37cdaf52-134f-59f8-8a7e-e1e0f7da853b', '58dbbc34-abff-51f2-a9d6-b199dd1a8bc0', 'Trusting the Refiner', 'Father, I am in the fire — I did not expect this season, I did not plan for this grief — and the heat has been greater than I thought I could bear.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dc4ba199-26e1-54dc-9320-326431ba9d1a', '58dbbc34-abff-51f2-a9d6-b199dd1a8bc0', 'The Exchange I Didn''t Ask For', 'Lord, I did not choose these ashes — this is not what I would have written for my life — and I am not going to pretend gratitude I do not yet feel.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3016c0c5-2dba-5115-9597-e03c49ec2836', '5b13fb24-c508-5622-9194-fdf1a2437a27', 'Grieving with Hope', 'Lord, someone I love is gone, and the world continues turning as if nothing has changed — but everything has changed — and I need to bring this weight to You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a3a17a1b-72ba-5414-9699-7f8e9451cfe3', '5b13fb24-c508-5622-9194-fdf1a2437a27', 'The Grief That Won''t Release', 'God, grief has settled into me in a way I didn''t expect — it ambushes me at ordinary moments — and I am learning that grief is love with nowhere to go.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('94dfb802-327d-5bf2-953e-988891f9ed3d', '5c6bf6ca-475b-5f5b-9537-0618f08756d0', 'Clothed in Forgiveness', 'Father, forgiveness is not a feeling I wait for — it is a decision I make in obedience to You, trusting that the feeling will follow the act of the will. Today I make that decision.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9a3fa533-b30b-54f2-8132-b138a706e26d', '5c6bf6ca-475b-5f5b-9537-0618f08756d0', 'Leave Your Gift at the Altar', 'Lord, You said to leave my gift at the altar and go be reconciled to my brother before offering worship — that means broken relationships are a worship issue, not just a relational one.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('430c0cda-eae7-5527-92c4-5eec0754c54e', '5d75f1c8-a6fc-557f-b655-fcf8eb915e75', 'Send Your Angels', 'Lord, I thank You that You have commanded Your angels concerning me — to guard me in all my ways, to lift me up, to keep my foot from striking a stone.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ae24cdb8-7fbc-5510-a70e-a5719c2a2a5d', '5d75f1c8-a6fc-557f-b655-fcf8eb915e75', 'Guarded in All My Ways', 'Father, You dwell in the secret place, and I choose to dwell there today — under the shadow of Your wings, in the shelter of Your presence, covered by Your faithfulness.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('35d304ee-98bf-5983-b771-8346fb85b2e5', '5e348795-7e64-5a5c-a827-131a30472878', 'A Sharp Instrument', 'Lord, I want to carry Your word with accuracy and with integrity — not words that come from my own imagination, but from genuine encounter with Your Spirit.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('98fa49a8-a646-5740-aee6-bca33e85e85f', '5e348795-7e64-5a5c-a827-131a30472878', 'Eagerly Desire', 'Father, Your Word says to eagerly desire the gifts of the Spirit, especially prophecy — so I come before You asking for a fresh activation of the prophetic in my life and in the church.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('334a5fdc-6f53-5fba-876d-ad3987b19c32', '601c4a8f-8ce6-5652-af39-845234fe2e05', 'No More Tears', 'Lord, one day You will wipe every tear from every eye — death will be no more, mourning no more, crying no more — and I hold that promise in one hand while I grieve with the other.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c147911f-3788-598f-9b8e-1c58f4fd2d49', '601c4a8f-8ce6-5652-af39-845234fe2e05', 'Mourning with Hope', 'Father, grief is the price of love — and I will not apologise for loving deeply or mourning fully. You grieve too. Jesus wept at a grave even knowing He was about to open it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('005a96c0-8701-501a-8f37-52afcb593fbd', '60c9ac16-98f5-5824-9dba-a4fcedb6914c', 'There Is No Fear in Love', 'Father, Your Word says perfect love casts out fear — and I want to understand that more deeply, not just in my mind but in the way my body and soul respond when fear rises.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cfde91b8-9f0a-53ff-a610-39fab527050e', '60c9ac16-98f5-5824-9dba-a4fcedb6914c', 'Made Perfect in Love', 'God, I want to love You more — not because I am trying to manufacture a feeling, but because I know that growing in love with You is the direct path out of fear.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('362ce44b-5c2d-5d35-a2e3-e3f1ac01ff1b', '6131c823-2b46-51de-8c11-5f241ceff907', 'Beautiful Feet', 'Lord, how beautiful are the feet of those who bring good news — and I pray today for every evangelist and missionary whose feet are walking toward people who do not yet know You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cb555852-46d2-5fc4-8429-1aa0c155848f', '6131c823-2b46-51de-8c11-5f241ceff907', 'Pray for Us', 'Father, Paul asked the Colossians to pray that God would open a door for the message — and I take up that same intercessory role today for the missionaries and evangelists I know and the many I do not.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4ccbb366-72d9-51ed-b072-f8b6b3fd4851', '61f1c0c4-b49c-5f66-afa2-ff46c64bb7c7', 'How Long Will Injustice Stand?', 'God, I see the injustice in this world and I cannot look away — the vulnerable exploited, the poor crushed, the powerful protected — and I am bringing my anger to You because I believe You share it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dc9a8b65-16c6-5440-ac69-61528a05f7c5', '61f1c0c4-b49c-5f66-afa2-ff46c64bb7c7', 'Crying Out for the Oppressed', 'Father, I am lament-praying for those who have no voice — for the ones being crushed by systems and powers that do not see them as image-bearers — have mercy.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('822f5a7a-bab0-5e82-a669-b1e82e2ffc12', '62d66610-522f-5b2d-aaf5-2f43f3234490', 'Releasing My Conclusions', 'Father, I have come to so many conclusions about my situation — most of them made in fear, and most of them wrong.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('fad085ba-d6c6-5de7-860d-bd05314c724f', '62d66610-522f-5b2d-aaf5-2f43f3234490', 'More Than I Can Figure Out', 'God, my mind works overtime trying to solve problems that only You can solve — and it is wearing me out.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b8b7d1da-d416-55dc-9b81-b8f809a86611', '65c1e072-966e-5143-9c04-96bfbf93e40c', 'Freedom from Repetition', 'Lord, I am tired of the cycle — tired of promising and failing, tired of the shame and the fresh start that doesn''t last.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bb5802d8-4f7e-5748-abdc-8419a08c6efe', '65c1e072-966e-5143-9c04-96bfbf93e40c', 'Sin Shall Not Have Dominion', 'Father, I have been in this cycle long enough — the same temptation, the same fall, the same guilt, the same resolution that lasts until the next time.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9c374804-9cb3-5721-8020-d2bc1a6fc4ab', '67812bc5-d9ac-548e-a9f1-a7b1e81f8fc9', 'Though the Fig Tree Does Not Blossom', 'Lord, Habakkuk taught me how to praise when everything is stripped away — when the fig tree does not blossom and the fields yield no food, yet I will rejoice in You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ac8bd35f-95c7-5334-9c3e-c5fbecd1805f', '67812bc5-d9ac-548e-a9f1-a7b1e81f8fc9', 'The God of My Salvation', 'Father, I confess that praise is harder when I am in pain — and yet something in me knows that this is exactly when praise costs something real.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3e5c58a2-e17f-5cf8-bc8a-b4a2c1e4b3ef', '682cf62e-d93c-5d3c-b7e8-dc102a8d9901', 'Why Are You Afraid?', 'Father, Jesus asked His disciples why they were afraid when He was in the boat — and I hear that question aimed at me today. Why am I afraid when You are with me?
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5f829706-7a8e-5151-897b-417c8415b15c', '682cf62e-d93c-5d3c-b7e8-dc102a8d9901', 'I Believe — Help My Unbelief', 'Father, I confess that I do not always believe You the way I say I believe You — my anxiety tells on me, my sleepless nights tell on me, the way I grip what I should be releasing tells on me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b9373517-351e-5f85-8710-be7b2d4c6700', '71281d1a-c92a-522a-83a9-44bccf69fb9e', 'Those Who Have Gone', 'Father, I thank You for those who have left the familiar to carry the gospel to places I will never go — their courage is a gift to the world, and I want to hold them up in prayer.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bb91d17e-c213-5526-b50a-2df5717cb03f', '71281d1a-c92a-522a-83a9-44bccf69fb9e', 'Grace for the Long Road', 'Lord, missionary work is long and often hard — years of language learning, of slow progress, of seeds sown without seeing the harvest. I pray for those in that place right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3f616781-9516-5585-a14a-d999bd7da5ed', '723b8f9b-2554-5524-aebd-c8348b2c2075', 'Let Everything Praise Him', 'Lord, let everything that has breath praise You — and I am one who has breath only because You gave it, so let me use it today to glorify Your name.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b28f2352-4418-5f55-bb79-47c5513c64e4', '723b8f9b-2554-5524-aebd-c8348b2c2075', 'I Will Not Stay Silent', 'Father, the Psalms teach me how to praise You — and today I come to school, ready to learn what it means to worship You with my whole being.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('06ef07b9-ffd1-5e79-ae9a-91d13d4d9fe8', '735640a9-cec6-5bf4-9e47-5a354a28343d', 'Whose Approval Am I Living For', 'Lord, am I now trying to win the approval of people, or of God? — Paul''s question is one I have to answer honestly today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('46f027d9-93fc-5225-aa09-25342a542010', '735640a9-cec6-5bf4-9e47-5a354a28343d', 'When Reputation Becomes an Idol', 'Father, I spend more energy managing how I appear than I do being who I actually am before You — and that gap needs to close.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0047d735-7f95-566d-ba2e-7e3cbfc2a1ea', '73e090e1-6637-5f11-b370-1f86ec1eb89e', 'Trusting When It Hurts', 'God, there is a part of this I do not understand — and maybe this side of eternity I never will.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4a099eef-edeb-5e3e-ac1b-147063172df1', '73e090e1-6637-5f11-b370-1f86ec1eb89e', 'Even This', 'Lord, this is not what I would have chosen — and I won''t pretend otherwise before You, because You already know.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6573e0ac-f0a8-5fb0-ace6-a37d038a82d4', '753e4f19-5672-54b5-a87b-1420b665d480', 'Mercy Over Judgment', 'Lord, I confess that I find it easier to criticise those in authority than to pray for them — today I choose intercession over commentary, and I ask You to change me in this.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a1147d0a-e6a4-57df-9b3a-382ffc371766', '753e4f19-5672-54b5-a87b-1420b665d480', 'For Those Who Govern', 'Father, Your Word calls me to pray for kings and all those in authority — so I come before You now on behalf of the leaders of this nation, whether I agree with them or not.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('003829d6-1c36-5a05-bef1-0145744a7f2e', '78db726f-e854-558e-8234-825fd218d1eb', 'Lord of Every Living Thing', 'Father, how many are Your works — in wisdom You made them all, and the earth is full of Your creatures and Your care.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2de019f9-b933-5565-af58-dad9c509e73a', '78db726f-e854-558e-8234-825fd218d1eb', 'The Works of Your Hands', 'Lord, thank You for the heavens that declare Your glory — every sunrise, every mountain, every ocean is a testimony to Your greatness.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('639293e7-aeff-5142-8348-be65528a776b', '7a2643f0-707d-544a-bf27-5a099edbd41a', 'When You Can''t Fix What They''re Going Through', 'Father, someone I love is hurting and there is nothing I can do to fix it — and that helplessness is its own kind of suffering.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7a9f9ca1-d879-50e6-b386-ca98136f69ab', '7a2643f0-707d-544a-bf27-5a099edbd41a', 'Releasing the Ones I Hold Tightest', 'Lord, there are people I love so deeply that my love for them has become a source of fear — fear of losing them, fear for their futures, fear that I won''t be enough for them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('26fc5207-915c-5a1f-b366-41367856eefd', '7a2db476-b9d5-5c89-91e3-5207ee2622b6', 'Love Without Limits', 'Father, I want to love my neighbours well — the literal ones, the ones I work with, the ones I share a city with — not in a vague way, but in a specific and costly way.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e436d421-27b1-5726-8cd8-70ed6676f254', '7a2db476-b9d5-5c89-91e3-5207ee2622b6', 'Who Is My Neighbour?', 'Lord, You said to love my neighbour as myself — and I know the question that follows, because it is the one I ask too — who is my neighbour? And I already know Your answer changes everything.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b25de713-0a0a-535b-9c7f-78b057d8c02d', '7b501149-17f6-5fd5-9264-500b4d694f94', 'Worthy Is the Lamb', 'Lord Jesus, heaven rings with the sound of Your worthiness — the angels cry it, the elders fall before You, and today I want to join that sound with everything I have.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f21bfc14-549c-5606-92f5-1fc6e7a83856', '7b501149-17f6-5fd5-9264-500b4d694f94', 'Every Knee Will Bow', 'Lord Jesus, You humbled Yourself to the point of death — and God has highly exalted You and given You the name above every name.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('363ab4d4-07ec-52fd-ad12-f6efb23d1690', '7bc2979d-ac9e-5bb7-bc88-c9698b78c70e', 'The Least of These', 'God, it is easy to love people who love me back — there is no virtue in that — but You call me to love the difficult ones, the unresponsive ones, the ones who take and don''t give.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9abb5467-ff8f-54d1-8ce6-b4568b71dd08', '7bc2979d-ac9e-5bb7-bc88-c9698b78c70e', 'Beyond What Is Natural', 'Father, I am asking You to give me a love for someone I find difficult — someone who does not make it easy, who does not seem to want what I have to offer.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6e844792-a6a0-553d-b656-1a37b4e5ed3a', '7c330400-c281-51a3-a59e-200e95d4d1b6', 'Hidden with Christ', 'Father, my life is hidden with Christ in You — the real me, the true me, the me You created, is safe in that place where no lie and no label can reach.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('936f3ae1-70fc-5ffa-8243-2cdf6ba953ce', '7c330400-c281-51a3-a59e-200e95d4d1b6', 'A New Creation', 'Lord, the old has gone and the new has come — I am a new creation in Christ, and I refuse to keep reaching back to an identity that was crucified with Him.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1d5d4b2c-1139-5abb-934f-7fad3d584ede', '7c4e9f3f-eb21-5184-8a2f-0af4e389eca8', 'An Anchor That Holds', 'Father, the waves have been high — the uncertainty has been real — and I need an anchor, something that holds me when everything else is shifting.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7ab9db18-7519-5904-99f6-a110cec0f9a1', '7c4e9f3f-eb21-5184-8a2f-0af4e389eca8', 'Standing on What You Have Said', 'God, I am returning to Your promises today — not because circumstances have made them easy to believe, but because I have decided to stand on them even when they are hard.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('845ab8d0-e249-5ecb-ba13-3ce591c27454', '7c72b753-20da-544b-ab34-260879285921', 'The Mind of Christ', 'Father, I have the mind of Christ — and today I want to live like someone who believes that, who leans into it, who lets that reality change the way I think about everything.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a4b23a59-64eb-5a22-a7df-71a48ae40a32', '7c72b753-20da-544b-ab34-260879285921', 'Transformed by Renewal', 'Lord, do not let me be conformed any longer to the pattern of this world — I want to be transformed, and I know that transformation begins in my mind.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('837dbf92-7f54-5cc6-b30b-f459351d7bda', '7d2c9ac2-d262-59eb-b89f-c8207c1352b7', 'The Snare of Fearing People', 'Lord, the fear of man has been a snare to me — I have made decisions based on what people think, shrunk back when I should have stepped forward, and performed for an audience of humans instead of living before an audience of One.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c28f125e-9cc0-577c-ae66-deb293c72734', '7d2c9ac2-d262-59eb-b89f-c8207c1352b7', 'When What Others Think Has Too Much Power', 'Father, I have been giving too much weight to what certain people think of me — their opinions have taken up more space in my head than Your truth.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('991e7237-4233-56a9-a208-b06da1eb1424', '7da89f77-4e27-50fa-a4a9-d96e6b244af2', 'Guard Me from Idols', 'Father, John''s warning at the end of his letter is brief and direct: keep yourselves from idols. I confess I have not always heeded it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c1bc0f5c-0683-5a6f-9a6b-41031e438e57', '7da89f77-4e27-50fa-a4a9-d96e6b244af2', 'The Things I Have Put Before You', 'Father, You said You are a jealous God — not in insecurity, but because You know that anything that takes Your place will ultimately destroy me. Today I confess that other things have taken Your place.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9cb81367-5c74-5edc-86ec-6f43b3d3c33b', '7e6a6fea-8500-5980-a79e-bb24ded42e92', 'Peace Where There Has Been Shame', 'Lord, there are things in my past that still surface and accuse me — seasons of failure, choices I am not proud of, words I cannot take back.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d2ec75f6-bf97-58fe-bc22-8371aebf8c46', '7e6a6fea-8500-5980-a79e-bb24ded42e92', 'Forgetting What Is Behind', 'Father, You told Your people "forget the former things, do not dwell on the past — see, I am doing a new thing." I need to hear that today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('23e8da02-973d-525f-84ea-dc3f3d9f5d3d', '7f365012-f29a-5bb4-af94-077b3fc3b4df', 'The Peace That Is a Person', 'Lord, peace is not just a feeling — it is a Person, and that Person is You. Jesus, You are the Prince of Peace, and where You are, peace is.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ea86a789-d46e-5302-bb90-e75e6a4fe8a5', '7f365012-f29a-5bb4-af94-077b3fc3b4df', 'Nothing Missing, Nothing Broken', 'Lord, You spoke shalom over Your people — a blessing so complete it covered every dimension of life: body, mind, relationships, future, and soul.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8e6d65c2-f192-535c-b1f6-60d04fd39369', '804e50c3-7251-53b8-9f4d-169100e1b5f1', 'Giving My Tears to God', 'God, I am grieving and I don''t know how to pray through it — so I am simply showing up, bringing my tears to You the way a child brings their pain to a parent.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cb6d6eb3-03b6-5cf2-a69f-a0ece3ef6bf4', '804e50c3-7251-53b8-9f4d-169100e1b5f1', 'Broken and Close to You', 'Lord, I am brokenhearted — not in a way that resolves quickly, but in a way that sits heavy and doesn''t lift — and I need to know You are close to me in this.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0602b5fb-46cd-5c72-bd7e-490c11cb3f3e', '81aa2d6a-563e-5f31-8b4e-482621ee1cef', 'Even in the Valley', 'Lord, even if I walk through the valley of the shadow of death, I will fear no evil — because You are with me. Your rod and Your staff, they comfort me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cecb70a9-da27-5bc1-93c4-85b418f296cd', '81aa2d6a-563e-5f31-8b4e-482621ee1cef', 'Where Death Has Lost Its Sting', 'Father, I have been confronted with my own mortality — whether through illness, loss, or simply the weight of knowing that life is not guaranteed — and fear has come.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('065a1c68-ab1b-58cf-adc4-58d95f79c3ec', '86854d73-be87-5967-80e1-574371f1f54f', 'I Have Sinned', 'Father, I come before You not with excuses or explanations, but with a simple confession: I have sinned against You, and I am sorry.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('810fdf8a-1dde-5cd6-b0c6-4b43d41b0de6', '86854d73-be87-5967-80e1-574371f1f54f', 'The Cleansing I Need', 'Father, create in me a clean heart — not just a pardoned one, but a renewed one. I do not want to carry forgiven sin forward as a habit. I want to be changed.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('599a982a-180f-5c76-9d2f-c1e5d1c19823', '8739835f-b61d-53c2-b743-494e47a1760f', 'I Am the One Who Has Seen Affliction', 'Lord, I will not dress this up — I am suffering, and the weight of it has driven me to my knees not in worship but in desperation, and I believe You can handle that.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8afaf62b-44d2-55ad-8865-180ab72a2bc8', '8739835f-b61d-53c2-b743-494e47a1760f', 'When the Pain Won''t Let Up', 'Father, I am in pain — physical, emotional, spiritual — and I have been here long enough that I am running out of ways to keep going, and I need You to sustain me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('20371e9b-006b-5c69-b18b-48f8c53da420', '87eda8b8-ecad-5203-8cff-7fb2d7d67efe', 'When Someone I Trusted Failed Me', 'Lord, it was not an enemy who did this — it was someone close to me, someone I trusted, and the wound has gone deep.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5175bbfa-57ef-5ff3-b6a5-cd7f29686598', '87eda8b8-ecad-5203-8cff-7fb2d7d67efe', 'Rebuilding Trust When It''s Been Broken', 'Father, betrayal has a long shadow — and even now it falls over the way I see people, relationships, and even You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e8ef2df3-9d07-5dae-8cad-0061e8afedd1', '88914936-5a73-5e30-8683-eea967dc2804', 'Boldness to Speak', 'Father, You promised power when the Holy Spirit comes upon us — power to be witnesses, not just to those nearby, but to the ends of the earth. I want to be part of that.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f5f90ad0-3070-5dc1-9d7e-6cf276a47bc8', '88914936-5a73-5e30-8683-eea967dc2804', 'A Life That Testifies', 'Lord, I want my life to be a witness — not just my words, but the way I love, the way I respond to hardship, the way I treat people who can offer me nothing in return.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8614e3b9-1be2-594f-bf40-aecf996d7f10', '88e40c1c-af0d-54fe-9f7d-12ba9139141e', 'Come to Me', 'Lord Jesus, You spoke these words to the tired and the burdened, and I hear them today as if You are speaking them directly to me — "Come to Me."
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e83a4e9d-85f2-5bf4-9b7f-a9d4936d6348', '88e40c1c-af0d-54fe-9f7d-12ba9139141e', 'My Soul Finds Rest in You Alone', 'God, my soul truly finds rest in You alone — but I confess I have been looking for it everywhere else first.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d78e001e-0f9b-5459-ba71-fdaa65dd0a8a', '8a861d44-7d6f-5aae-b2e4-9e54c14ab948', 'Quieting the Noise Within', 'Father, the world outside is loud but the loudest noise is inside my own head — and I am tired of fighting thoughts that seem to have a life of their own.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ed98cc2e-98ee-52d5-91fa-d66bfa37a3df', '8a861d44-7d6f-5aae-b2e4-9e54c14ab948', 'The Peace of a Steadfast Mind', 'Lord, my mind has been loud — cycling through the same fears, replaying the same conversations, rehearsing every possible outcome.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('40a15e05-998d-507b-b392-80f3a630e378', '8aa5bb29-58f1-5cfa-871f-fec97be028eb', 'Do Not Worry about Tomorrow', 'Jesus, You looked at the birds of the air and the flowers of the field and used them to teach me not to worry — You said my Father feeds and clothes them, and I am worth far more.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b94d56a6-5d73-5265-b014-67f1c9f42704', '8aa5bb29-58f1-5cfa-871f-fec97be028eb', 'Breaking the Cycle of Overthinking', 'Lord, my mind has a well-worn path of worry — I know the route so well I walk it without even deciding to.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('83bb5d7a-427f-5f1b-9a2b-2ab92d629b81', '8bd8aee2-0bd1-5639-a20c-9d0821163373', 'Your Glory Fills the Earth', 'Father, the seraphim covered their faces before You — and the more I understand who You are, the more I understand why. You are altogether holy and I am not.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('89b1f262-4053-5315-b84d-b1715dbafa1e', '8bd8aee2-0bd1-5639-a20c-9d0821163373', 'Slow to Anger, Abounding in Love', 'Lord, You proclaimed Your own name to Moses — compassionate and gracious, slow to anger, abounding in love and faithfulness — and I declare that same name over my life today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3cbf707c-fcfa-5593-9b78-50bff937d6d9', '8dfbb36f-e363-5b92-82d2-6caae3f4add8', 'None of These Things Move Me', 'Lord, Paul was warned of chains and tribulations ahead — and he kept going. I ask for that same holy resolve when the path of obedience becomes difficult.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('53da0545-9b91-5796-abfc-92017b944569', '8dfbb36f-e363-5b92-82d2-6caae3f4add8', 'Finish the Race', 'Father, Paul said he did not count his life dear to himself, that he might finish his course with joy — let that be the cry of my heart today and every day I have breath.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('621fa6f4-06b0-5b18-a81e-e641c9b33ab0', '91179290-896b-547a-9dcb-10fa240322fa', 'The Sin I Barely See', 'Father, pride is the sin I am least likely to confess because it is the one I am most likely to miss — it disguises itself as confidence, as competence, as self-sufficiency, and I have welcomed it in.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b850fe4c-3646-53aa-a958-a194e9d49bfc', '91179290-896b-547a-9dcb-10fa240322fa', 'I Cannot Do This Without You', 'Father, I come to You not with confidence in myself but with the honest admission that I have been living as though I do not need You — and it has shown.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('15b86937-6c6d-5a0c-9df1-459ca904572d', '9346bebe-2bc9-548a-b639-b972b2130e6e', 'Free Me to Forgive', 'Father, I need Your help to do what I cannot do on my own — I cannot manufacture forgiveness for what was done to me. But You can do in me what I cannot do for myself.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('841406c0-0f34-5ff7-82b9-73baaf10ad20', '9346bebe-2bc9-548a-b639-b972b2130e6e', 'The Debt I Will Not Forgive', 'Father, I confess that I am holding something against someone — and I have been holding it long enough that I have begun to call it justified, even righteous, when it is neither.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('aa2c22df-400a-509a-aed7-356642ce7b3b', '93766ec3-a2ff-5856-9d31-aa926707663a', 'Made and Known and Loved', 'God, I struggle to receive love because I know what is inside me — the failure, the inconsistency, the gap between who I want to be and who I actually am — and it is hard to believe anyone who knows all of that would still choose me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f89f840e-3935-5419-ab93-e37b9103c8d7', '93766ec3-a2ff-5856-9d31-aa926707663a', 'You Rejoice Over Me', 'Lord, there are days when I find it hard to believe that I am lovable — days when I know my own darkness too well, when shame speaks louder than grace.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e84a09a2-5d71-5b52-8910-395dbdeb1298', '93dfe0f2-52ef-59db-ba64-178d7d5d17e9', 'Sent by God', 'Lord, I thank You for the people You have sovereignly placed in my life — the ones whose arrival I did not plan but whose presence I cannot imagine living without.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f6fc3139-2dfb-57ce-811b-f87d0e58e118', '93dfe0f2-52ef-59db-ba64-178d7d5d17e9', 'Ordered Connections', 'Father, You know every relationship in my life — the long-standing ones, the new ones, and the ones that have not happened yet but that You are already planning.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1f47dd15-d858-503e-a759-4ed998e31391', '9535a447-8a0f-5176-8f15-1d222afb8c81', 'To the Ends of the Earth', 'Father, I was not made only for my neighbourhood or my nation — I was made for the whole earth, and the prayer life You are forming in me must stretch to the edges of the world.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e62028bd-bd09-59a4-9a31-dd6ee1e66b5f', '9535a447-8a0f-5176-8f15-1d222afb8c81', 'Ask of Me', 'Lord, You said to Your Son: ask of Me, and I will give You the nations as Your inheritance, the ends of the earth as Your possession — and I ask in agreement with that prayer today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('484d9615-c5a6-5b34-b315-67c675372a5f', '982d6895-66f2-5571-a1e2-abedbe039326', 'Heal Our Land', 'Father, I confess on behalf of my generation that we have worshipped things other than You — comfort, progress, autonomy, and prosperity — and we have expected Your blessing without Your lordship.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d815f317-ed2a-5c76-9d3f-920641a217e0', '982d6895-66f2-5571-a1e2-abedbe039326', 'Standing in the Gap', 'Father, Daniel prayed as though the sins of his nation were his own — he did not stand apart from them, but identified himself with his people before Your throne. I want to pray that way today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('721a34d4-b216-59e2-811c-41ee39b2ccec', '9adbff92-13f9-515b-b147-40fa89143c2a', 'A Sanctuary Set Apart', 'Father, I acknowledge that my home is not just a physical structure — it is a spiritual environment, and I am responsible for the atmosphere that fills it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ae5e612c-554b-50ae-a756-26971f2dec6d', '9adbff92-13f9-515b-b147-40fa89143c2a', 'As for Me and My House', 'Lord, I make the same declaration Joshua made: as for me and my house, we will serve the Lord — and I mean it not just as a sign on the wall but as a daily, costly choice.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('889a9fb8-f235-53b7-bf9a-eff1ddf6ac97', '9b0cdabf-456b-519d-90c4-60679f5a8017', 'When Hope Deferred Has Become Heavy', 'Father, hope deferred makes the heart sick — that is not a metaphor for me right now, it is a diagnosis — and I am bringing the sickness of deferred hope to the only one who can heal it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f21f9858-c1da-55df-9b90-b33d18a7899c', '9b0cdabf-456b-519d-90c4-60679f5a8017', 'Starting Again', 'God, I have been disappointed — by circumstances, by people, and if I am honest, sometimes it has felt like disappointment in You — and I am not going to pretend otherwise.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2d9d2626-0a88-5432-b7e6-a99cecf906b5', '9b7b29f5-efc0-5ca1-bc8f-557e28a631be', 'Anger That Has Become a Home', 'Father, I have let anger settle in me like a resident rather than a visitor — and I confess that I have excused it, justified it, and in some ways enjoyed the sense of power it gives me over those who have wronged me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('77184c3f-ebf3-592a-beb8-b7856f914cc3', '9b7b29f5-efc0-5ca1-bc8f-557e28a631be', 'The Fire I Have Kept Burning', 'Father, I confess that I have given the enemy a foothold — I have let the sun go down on my anger more times than I can count, and what started as a legitimate hurt has curdled into something uglier.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('586e44e6-37b2-5087-9c49-31c02a2812e4', '9cafb9fc-7600-5ab5-b750-e733923ead3e', 'You Made All Things', 'Lord, You are worthy to receive glory and honor and power — You created all things, and by Your will they exist and were created.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9e9228e6-56f1-5e40-ba29-d61c4a92c353', '9cafb9fc-7600-5ab5-b750-e733923ead3e', 'Come, Let Us Worship', 'Lord, You invite me to come and worship, to kneel before You, the Lord my Maker — and today I accept that invitation with my whole heart.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ebb4ee84-8f87-5054-abdd-70ecd9dc432a', '9cb089b9-752f-5d1a-8a7d-09c7ace44097', 'A Friend Who Sticks Closer', 'Lord, loneliness is a real ache — and I am not ashamed to name it before You. I ask You to fill it, first with Yourself, and then with the right people.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ecca46f9-29a1-56c1-bead-4eded682da32', '9cb089b9-752f-5d1a-8a7d-09c7ace44097', 'Iron Sharpening Iron', 'Father, You said it is not good for man to be alone — and I feel the truth of that in my bones. I ask You for the gift of real, faithful, Jesus-centered friendship.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('55fcb740-27f5-55f2-b042-5f9db7a46f34', '9d1aebfc-8154-5ec6-9f93-29efde13772a', 'He Always Provides', 'Father, Your Word says You always provide a way of escape when I am tempted — always, not sometimes, not when I deserve it, but always.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dd1acddb-876f-573e-b9b2-3ef683817539', '9d1aebfc-8154-5ec6-9f93-29efde13772a', 'Taking the Way Out', 'Lord, I have not always taken the way of escape — sometimes I have hovered at the edge, waiting, until the edge became the fall.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6514105a-8ddf-5f2a-b150-548efbcc027a', 'a059bd90-4e20-5169-93f2-dbca8ff2d9f6', 'Freedom from Lack', 'Lord, generational poverty is more than just financial — it is a mindset, a spirit, a pattern that runs through families and through time. I ask You to break every dimension of it in mine.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6b865ca6-1358-5dc0-9146-d8f6f24e1b05', 'a059bd90-4e20-5169-93f2-dbca8ff2d9f6', 'Lifted from the Dust', 'Father, You raise the poor from the dust and lift the needy from the ash heap — I come before You today believing that what has been the story of my family does not have to be the story of my future.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0a100164-57bb-5037-bf82-ac7ea91b82e0', 'a17e78b4-9cce-5a32-8867-de3bcf51844e', 'Saved to the Uttermost', 'Father, You gave Your only Son not to condemn the world but to save it — that truth is too great for me to hold, but I reach for it today with everything I am.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('91e83457-9af9-5254-80bd-16df28da01bd', 'a17e78b4-9cce-5a32-8867-de3bcf51844e', 'What Grace Has Done', 'Lord Jesus, thank You — I was dead and You made me alive, separated and You brought me home, not because I earned it but because of the great love with which You loved me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('675aab48-5bd6-5304-b3b2-42f16dae1fb8', 'a38af66d-8d0b-56d8-95f1-a12be8ec1314', 'Built on Love', 'God, I want to build my life on something that cannot shift — and Your love is the only foundation that will not move, not when circumstances change, not when feelings fluctuate.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('db5ad7f2-86b7-5f8d-b892-7a95c1b5d58c', 'a38af66d-8d0b-56d8-95f1-a12be8ec1314', 'Deep Roots', 'Father, I want to be rooted and established in Your love — not just believing it intellectually, but anchored in it so deeply that nothing can uproot me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('79fc84fc-7d40-5344-9713-a60c84228901', 'a42139df-4254-5834-90a5-62dbeb7e1e76', 'Weapons of the Spirit', 'Lord, Your Word tells me the weapons I fight with are not of the flesh — they have divine power to demolish strongholds, and I need that power working in me today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7da06448-67fa-5803-a0e0-c7c6499c680a', 'a42139df-4254-5834-90a5-62dbeb7e1e76', 'Casting Down Imaginations', 'Father, I confess that I have sometimes allowed my imagination to build a world shaped by fear, by past wounds, and by the enemy''s narrative rather than by Your Word.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('40ca539c-d510-52d2-bd56-d0a40c8243db', 'a7468f1d-1f5e-598f-ac50-14b52bcb366b', 'Healer of the Broken', 'Father, You are the Lord who heals — not as an occasional exception but as an expression of who You are — and I come to You now on behalf of those who are suffering in body.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('53fb12cf-d267-5be0-9cda-d31682c6752a', 'a7468f1d-1f5e-598f-ac50-14b52bcb366b', 'Lay Hands on the Sick', 'Lord, I confess I have sometimes shrunk back from praying boldly for healing because I was afraid of what would happen if nothing changed — but fear is not a good reason to withhold prayer.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5a7e794b-af5a-577a-9fed-22c6843363ef', 'a7700e7f-b5e0-557b-a900-b520e6cf3f13', 'Pride Goes Before a Fall', 'God, Your Word is clear: pride goes before destruction, and a haughty spirit before a fall — and I don''t want to learn this lesson the hard way.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9f3c1e32-70b0-5856-995b-51d6b869f6ba', 'a7700e7f-b5e0-557b-a900-b520e6cf3f13', 'A Warning I Need to Hear', 'Father, I am in a season where things are going well — and I know from Your Word that this is when pride is most likely to take root.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('08907b20-1835-5011-aeb2-bb3b6cc3266f', 'a7e0b169-26f0-529c-bf00-844f48a06405', 'Let It Flow', 'Lord, I want to go everywhere doing good and healing all who are oppressed — the same Spirit that was on Jesus is on me, and I refuse to live below what that means.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4c49a129-5ce4-52e2-8d55-8b82471d7a64', 'a7e0b169-26f0-529c-bf00-844f48a06405', 'Fresh Oil', 'Father, I come before You asking for fresh oil — a new and living anointing that refreshes what has grown stale and revives what ministry and life have worn down.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('13adaa03-5f75-5c09-9ed6-2fcce81ce0b9', 'ab01fdde-8573-5b74-975f-14ea7de1320d', 'Sent Ones', 'Father, You set apostles in the church first — not as a title to be chased, but as a function to be filled: building, establishing, planting, and bringing order to Your house.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4fc4dbe4-45ac-5bc5-8dd6-726c21fb94cc', 'ab01fdde-8573-5b74-975f-14ea7de1320d', 'Build What Lasts', 'Lord, apostolic ministry exists for the equipping of the saints — not to build platforms, but to build people who are mature, whole, and deployed in their calling.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('17e7dc60-b8f5-5fee-9922-768b9b0839bc', 'acf8844e-8fec-5c77-979c-fefc45463f59', 'Humility as a Way of Life', 'Father, humility is not about thinking less of myself — it is about thinking of myself less, and of You and others more.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2c49fa9f-19b3-5679-bbad-bee414cd7079', 'acf8844e-8fec-5c77-979c-fefc45463f59', 'The Simple, Daily Ask', 'God, You have told me what is good and what You require — to do justice, to love mercy, and to walk humbly with You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5d5b7718-e933-5ba6-a7e2-c228699f026c', 'ae2166e4-8a14-55ec-b27e-3df697af7ff1', 'He Directs His Steps', 'Father, Jehoshaphat stood before a vast army with no strategy and turned to You — and You told him not to be afraid or discouraged, that the battle was Yours. I receive those same words today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('baad78e5-b270-5ac8-9892-bc24fd14d3e1', 'ae2166e4-8a14-55ec-b27e-3df697af7ff1', 'Our Eyes Are on You', 'Lord, I do not know what to do — and I am saying it plainly, because that is what Jehoshaphat said, and You honored his honesty with Your presence and Your power.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7c0ac7b8-8afd-5ade-aafe-e00a26e0a6bf', 'af70a036-452e-5232-9911-9b7787b18547', 'Present Every Person Complete', 'Father, I carry in my heart the people I have the privilege of leading and pouring into — I bring them before You today because the burden of discipleship is more than I can carry alone.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b7a90b5d-c330-5626-9b1d-9ffac931fe71', 'af70a036-452e-5232-9911-9b7787b18547', 'Faithful to Entrust', 'Lord, Paul said the things he heard, Timothy was to entrust to faithful men — let me be a faithful leader who gives away what I have received rather than hoarding it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6e64a87a-1427-536e-b306-9a627e942323', 'aff81d13-a5f1-572b-a547-9ec7f7520443', 'Light in the Workplace', 'Father, I thank You for the workplace You have placed me in — the people I work alongside, the problems I am given to solve, the position of influence I may not fully recognise yet.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d81e2ddd-6423-5af2-a3d7-8e44896ad167', 'aff81d13-a5f1-572b-a547-9ec7f7520443', 'A Witness Where I Work', 'Lord, I ask for divine appointments in my workplace today — unexpected conversations, moments where a colleague opens a door I did not know was there, opportunities to show the love of Christ in practical ways.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7d72c3a8-dd44-563b-a4d4-cb9c9b3af8ae', 'b034f6f0-6f9b-5ee6-92b8-0d88c77cd86b', 'If My People', 'Lord, You gave a clear and searching promise: if My people who are called by My name will humble themselves and pray and seek My face and turn from their wicked ways — then You will hear.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e9cca7e5-45d8-554b-b2ea-9bcbeb2e58b6', 'b034f6f0-6f9b-5ee6-92b8-0d88c77cd86b', 'Light in the Darkness', 'Father, my nation has gifts and flaws, history both honourable and shameful, a future that is uncertain — but it is not outside Your reach or beyond the power of Your Spirit to transform.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('95b7e8f3-e760-5db7-b32d-69886a7ea3c8', 'b06cc38a-6538-5c23-9b3a-049ed00cdf89', 'You Are God and I Am Not', 'Lord, the simplest and most needed truth I can come back to today is this: You are God and I am not.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('eb294b0f-1a7e-5a10-b9ba-5b7fe87b0022', 'b06cc38a-6538-5c23-9b3a-049ed00cdf89', 'Lower Myself Before You', 'Father, You promise to lift up those who humble themselves before You — and I want to practice that today, not as a technique but as a genuine posture of heart.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('77782d33-5f99-5f0e-ba28-dc7a99198008', 'b11a09a0-6c96-5a65-ab30-1c7908a9c92b', 'The Prayer I Have Not Prayed', 'Father, I confess that I have not prayed the way I know I should — not consistently, not persistently, not with the kind of faith that believes prayer actually changes things.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dddf6cf4-7321-5400-ab43-da6058be4032', 'b11a09a0-6c96-5a65-ab30-1c7908a9c92b', 'Too Busy to Pray', 'Father, I have been too busy to pray — and I confess that busyness is often my excuse for avoiding the one thing that would make everything else make sense.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('37484038-8b0a-5506-bb36-d29e3b73e9b4', 'b261bdb4-ddb2-5063-938a-d233f945f782', 'Standing in the Victory Already Won', 'Father, I am not fighting for victory — I am fighting from it. Jesus has already won, and the enemy is already defeated.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5380e563-a3ff-591d-b23c-26cacf56eb9a', 'b261bdb4-ddb2-5063-938a-d233f945f782', 'The God of Peace Will Crush Him', 'Lord, Your Word says the God of peace will soon crush Satan under our feet — and I stand on that promise today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4fd2c20e-6ac7-50ea-9d52-bc736b346694', 'b4834bbb-05b5-50e9-af9e-8fe901dfbcbf', 'You Do Not Grow Weary', 'Lord, You do not faint and You do not grow weary — and in this season of depletion, I need to draw from Your reserves rather than my own.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b5123e91-29e4-5388-be26-efe2bca01cd2', 'b4834bbb-05b5-50e9-af9e-8fe901dfbcbf', 'Renew My Strength', 'Father, I am tired — and I am not ashamed to say so before You. Ministry is beautiful and it is also demanding, and I am running on empty more days than I want to admit.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('09de2bd5-7530-5748-b848-ac4da4f4cddb', 'b5ca395f-9310-5879-a710-0c67eff1d12d', 'I Will Set No Worthless Thing', 'Father, I live in a world of infinite content and finite willpower — and I confess that I have not always been a wise steward of what I allow through my eyes and into my mind.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('999c7b6c-6932-5508-a979-cd5f584c63ca', 'b5ca395f-9310-5879-a710-0c67eff1d12d', 'A Guarded Screen and a Guarded Heart', 'Lord, the access I carry in my pocket to everything — good and terrible — is unlike anything any generation before me has faced.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0e3ea902-76e4-59c4-bbfe-e7dc46646872', 'b6a4999e-f745-5862-8a48-bb1021ccd1fb', 'Releasing What I''ve Held', 'Lord, Simon was told he was in the gall of bitterness — and I wonder if someone would say the same of me if they looked closely enough.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('74126acd-de16-5d31-94f3-6076609734cd', 'b6a4999e-f745-5862-8a48-bb1021ccd1fb', 'The Root I''ve Let Grow', 'Father, I think bitterness has been growing in me longer than I realized — and it has affected more things than I can even track right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('85e13589-c85b-5134-b8cd-e30a233d6cc5', 'b74fafe3-d093-5ee9-94a4-bdd40e121a54', 'The Trap of Looking Sideways', 'God, I have been comparing myself to others — and it always ends the same way: either in pride because I''m ahead, or in envy because I''m not.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8c5fc7f7-bfc4-596d-b405-4e75ad541a2d', 'b74fafe3-d093-5ee9-94a4-bdd40e121a54', 'Celebrating What You Gave to Someone Else', 'Father, I want to rejoice with those who rejoice — but there are times when someone else''s good news quietly stings, and I don''t always handle that well.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b28a4e9a-d1c9-5ce9-9c3d-74ab17f6a548', 'ba8a5e19-79ec-5765-b7c8-783738222870', 'The Year of the Lord''s Favour', 'Lord, You bind up the brokenhearted — not eventually, not conditionally, but as a promise rooted in who You are and what You came to do. I receive that promise today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f47f42b4-0518-5c3c-9de3-608c6ade4afc', 'ba8a5e19-79ec-5765-b7c8-783738222870', 'Healed and Whole', 'Father, You heal the brokenhearted and bind up their wounds — that word "binds up" speaks of careful, intentional attention. You do not rush past my wounds. You tend them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('34102e46-29c1-5116-8b9b-f6c739976d7d', 'baec1302-c274-5333-87d7-094c3097d4c5', 'Renewed in the Spirit', 'Holy Spirit, I need You today not as a memory but as a present, living reality. Come and refresh what time and trial have worn down in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('58630096-25aa-5bd4-9324-285726900a01', 'baec1302-c274-5333-87d7-094c3097d4c5', 'Fill Me Again', 'Father, Your Word commands me to go on being filled with the Spirit — not a one-time experience to look back on, but a daily, ongoing receiving from You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b48525f2-3c16-515f-8ba7-b80122167e88', 'bc446a3d-b8bc-58f5-96fb-207768bb65cf', 'Uphold the Servants', 'Father, I lift before You those who serve Your people as pastors, preachers, teachers, and ministers — the men and women who carry the weight of shepherding others toward You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d943a54b-dac2-5962-80a7-5a742e72f24a', 'bc446a3d-b8bc-58f5-96fb-207768bb65cf', 'Wrestling in Prayer for Others', 'Lord, I thank You for the Epaph-rases in the body of Christ — those who wrestle in prayer for their congregations, who stand in the gap even when no one sees them doing it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6942990a-8525-5b5a-b061-8bd7971980f5', 'bd6798ff-c536-59c9-b888-6e9759c0bbf8', 'He Will Make Your Paths Straight', 'Father, I acknowledge You in this decision — I bring it before You openly, I ask for Your mind on it, and I commit to following Your lead even if it is not the path I would have chosen.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7f1291d7-d532-5077-9588-6e7a689ddce9', 'bd6798ff-c536-59c9-b888-6e9759c0bbf8', 'Trust in the Lord', 'Lord, I want to trust in You with all my heart and lean not on my own understanding — but I confess it is hard to stop relying on what I can figure out on my own.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0d890b54-c51d-55fb-af7f-d0d8fb505409', 'be03e8bf-83df-5b30-80fd-430b94efa3d8', 'Firm and Secure', 'God, it is impossible for You to lie — You have sworn by Yourself, the highest oath there is — and that unchanging character is the anchor my soul needs in this season.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ff784df4-0d12-57c5-beb8-4942aaaab7ff', 'be03e8bf-83df-5b30-80fd-430b94efa3d8', 'Going Behind the Curtain', 'Lord Jesus, You entered the inner sanctuary on my behalf — You went behind the curtain — and my hope is anchored there, in what You have already accomplished in the holy of holies.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ce156222-3062-56c9-875f-6178895cab98', 'c04a05dc-489b-56d3-a09a-02b3f5ad1b4a', 'The Long Road of Forgiveness', 'God, You call me to forgive — not seven times but seventy times seven, and that number is so large it has to be about something other than math.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e33ec8c5-29e3-59a7-8862-838bac4f5c42', 'c04a05dc-489b-56d3-a09a-02b3f5ad1b4a', 'When Resentment Keeps Coming Back', 'Father, I thought I had forgiven this — and then something reminded me of it, and the anger came rushing back like I''d never let it go.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('34a25fc8-cfee-5acf-a3a4-2796baefbeab', 'c0d58348-02da-59a3-80f8-d3edf1ae92ef', 'A Covenant with My Eyes', 'Father, Job made a covenant with his eyes — a deliberate, intentional decision about what he would and would not look at — and I want to make the same covenant today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6d024af0-af3f-5947-bad1-c95dae2b96cb', 'c0d58348-02da-59a3-80f8-d3edf1ae92ef', 'What I Look at Shapes What I Long for', 'God, I am learning that what I consistently look at becomes what I consistently desire — and I want to be intentional about what I am cultivating in myself.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6c50e336-e5f9-5fb6-b4d6-a61184d38aca', 'c11cb213-a914-595a-a32b-074845aca9c8', 'Life More Abundantly', 'Lord Jesus, You came that I might have life and have it to the full — not a half-life, not a going-through-the-motions life, but a life that overflows with meaning and purpose.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f6ea9c22-d542-566c-812f-cfa9479f9138', 'c11cb213-a914-595a-a32b-074845aca9c8', 'He Satisfies the Thirsty', 'Father, the emptiness I sometimes feel is not a sign that something is wrong with me — it is a sign that I was made for You, and only You will do.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0e86ff96-3aca-5c41-bef7-f259c00509ce', 'c184b3b3-bd6d-5de6-99cf-e6fafe5abd2a', 'The Years the Locust Ate', 'Lord, You promised to restore the years that the locust has eaten — and I bring You the years I have wasted, the seasons lost to my own failures, and I hold You to that promise.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c114204d-723e-5529-a400-6b785b978228', 'c184b3b3-bd6d-5de6-99cf-e6fafe5abd2a', 'I Will Rise', 'Father, restoration is Your specialty — You restore souls, You restore years, You restore people — and I come to You today as someone who needs the full measure of that restorative grace.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6cac2673-b851-59c7-b1e1-ee145ba02c0e', 'c3d24bc2-c8a1-588c-b038-17004ad3c8ef', 'First, Reconcile', 'God, Your Word says to leave my gift at the altar and go be reconciled to my brother — that reconciliation matters so much to You that it interrupts worship.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('de9cadc3-5da7-5b86-b6bb-168b136cd8cd', 'c3d24bc2-c8a1-588c-b038-17004ad3c8ef', 'What They Did Was Wrong', 'Father, what was done to me was wrong — and I am not going to minimize it before You, because You see it clearly and You call it wrong too.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0c2224b6-714e-52ef-afa3-f59f702db680', 'c4513324-e958-5f36-8b6f-ff97c41adfc3', 'When the Body Is Not Cooperating', 'God, I am struggling with my body and it is affecting everything — my ability to show up, to be present, to hope — and I need You to meet me in the physical as well as the spiritual.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('55bb8c5e-671b-5ecd-a0b4-31ddabe4a5bb', 'c4513324-e958-5f36-8b6f-ff97c41adfc3', 'Healer, I Need You', 'Lord my God, I cried to You for help and You healed me — I am standing on that testimony, bringing this body and this pain and this fear before You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3c44df13-5b55-5b6d-afeb-e64350ec29ce', 'c48679b3-b623-5f0f-92f2-8eff974cb9c8', 'Plans to Give Me a Future', 'Father, You said You know the plans You have for me — plans for welfare and not for evil, to give me a future and a hope — I am holding onto that when my future feels uncertain.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bf66cb52-b068-5101-b6e4-5087eb3bf2e4', 'c48679b3-b623-5f0f-92f2-8eff974cb9c8', 'Trusting What I Cannot See', 'God, the future feels unstable — the plans I had have not held — and I am asking You to be the stability that my circumstances cannot provide.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c1b1cbb9-b4b8-530d-95c4-5d121d11d2f9', 'c4ce4c21-7165-5fe8-8255-d16fc06c89aa', 'When Failure Feels Like the End', 'Father, I have already failed at something — and right now the fear is not just of future failure, but of whether I can recover from what has already happened.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ce232aa7-e61a-52e3-a721-88b1b92d1cd2', 'c4ce4c21-7165-5fe8-8255-d16fc06c89aa', 'If God Is for Me', 'Lord, there is something in front of me that I am afraid to attempt because I am afraid to fail — and that fear is keeping me smaller than You made me to be.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('331f23d6-3771-57f1-9787-c8f68e2ed25d', 'c609c559-ba8c-551d-b9f5-b8840265ea0f', 'You Have Been Faithful', 'Lord, Your mercies are new every morning — great is Your faithfulness, and I have lived long enough to see the evidence of that in my own story.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('4467ea69-2af0-582b-9685-46b1b6203739', 'c609c559-ba8c-551d-b9f5-b8840265ea0f', 'Give Us This Day', 'Father, thank You for daily bread — for food on the table, air in my lungs, and strength to rise this morning, gifts I receive without deserving them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0765aa9a-ab4c-5bb0-b328-e909bbe5bb2e', 'c73d3c21-cea8-55d9-9ae8-26cfa6de78b1', 'A City on a Hill', 'Father, a city on a hill cannot be hidden — and the church was never meant to be invisible, irrelevant, or so absorbed in its own internal life that it fails the community around it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('90426c07-0afe-5bc3-b671-afa9ed6e7cd3', 'c73d3c21-cea8-55d9-9ae8-26cfa6de78b1', 'Seek the Peace of the City', 'Lord, You told the exiles in Babylon to seek the peace and prosperity of the city where You had placed them — to pray for it, to serve it, to build in it even in a foreign land. That is my assignment here.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('85492d36-3b16-5379-ba2e-5e3b98176521', 'c754f9ae-b6a1-5b9a-b290-c65a4c18010e', 'Cover Them Today', 'Father, I come before You today lifting up my spouse by name — You knit them together in their mother''s womb, and You placed them in my life by Your design.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f7860206-ae17-58c3-aa9e-8199eb40954b', 'c754f9ae-b6a1-5b9a-b290-c65a4c18010e', 'Strength for My Partner', 'Lord, You know my spouse better than I do — You see every hidden struggle, every silent prayer, every hope they are still holding onto.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('01882f83-496f-5e17-b817-f41c15352e22', 'c922c587-8f5b-542d-83aa-f7b57c6d0b4c', 'You See It All', 'Father, I cannot always explain what I feel or trace exactly where the pain began — but You know. You see the whole story, and You are not confused by any part of it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9c41a5f0-9e82-59db-b1a0-f16b757d5e65', 'c922c587-8f5b-542d-83aa-f7b57c6d0b4c', 'A Contrite Spirit', 'Lord, You do not despise a broken and contrite heart — You said so, and I hold on to those words today because my heart is broken and I need to know You are not turned away by it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7f692e17-75cf-57bf-8f43-8c95a2a01929', 'c95a4cea-5282-5bac-9410-89e1ce4e8f74', 'When Hope Is an Act of Will', 'God, hope does not feel available to me right now — it feels like something other people have — and I am asking You to be my hope when I cannot produce it myself.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c08902db-85e2-5478-8ff7-34d094916805', 'c95a4cea-5282-5bac-9410-89e1ce4e8f74', 'Because of This I Have Hope', 'Lord, I am calling something to mind because I have to — because my feelings are telling me one story and I need Your Word to tell me another — Your mercies are new every morning.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('35c77f42-9d59-5032-9558-1740ddcdf35b', 'cb89d8fa-a518-56c4-92bd-8b5a6e6ec881', 'My Times Are in Your Hands', 'Father, I trust in You. Those words feel both true and costly right now — because what I am trusting You with is my future, and it is unclear to me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('699682bf-af4e-5013-ba51-f34740282a80', 'cb89d8fa-a518-56c4-92bd-8b5a6e6ec881', 'Trusting God with What I Cannot Control', 'God, the future feels like standing at the edge of a cliff in the dark — I know the next step exists, but I cannot see where it lands.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c017d541-84e5-5125-8a14-4a4b547019f1', 'cc505e29-758a-58fe-b390-b828591f6160', 'Everything I Took for Granted', 'Father, Your Word tells me to give thanks in all circumstances — not for all circumstances, but in them. I confess that I have given thanks for very few, and complained about many.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ced31843-8e3d-5921-8e6a-3e32ad12529a', 'cc505e29-758a-58fe-b390-b828591f6160', 'I Forgot to Thank You', 'Father, there are things I have prayed for that You gave me, and I received them and moved on without pausing to thank You — like the nine lepers who were healed and kept walking.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('9cf88c1b-6fa0-5985-b890-338a4fad68f7', 'cd2860b3-effa-5593-818b-0899a7e54184', 'When Faith Feels Like It''s Not Enough', 'Father, the disciples asked You to increase their faith — and I make the same request, because mine feels thin right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('ca6f340d-49ee-5509-a7eb-54f2a639e3f3', 'cd2860b3-effa-5593-818b-0899a7e54184', 'Choosing to Believe What I Cannot See', 'Lord, faith is not the absence of doubt — and I am grateful that Your Word doesn''t ask me to pretend I have no questions.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a368b195-82fe-5d9e-9a52-2b1ce17c73c9', 'cf47ea2d-615f-593b-a9ac-771d8fb57738', 'Relief from the Weight of It All', 'Lord, stress has become the background noise of my life — a constant hum of pressure that I have started to think is just normal.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b77c4eb6-0eb4-5785-a1b0-d1537275ac53', 'cf47ea2d-615f-593b-a9ac-771d8fb57738', 'Come to Me, All Who Are Weary', 'Jesus, I am weary. Not just tired — weary in the bone-deep way that sleep does not fix, because it is not just physical exhaustion, it is the weight of everything.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('07cdbeab-c09f-5bfb-be1c-01ea60c8c17d', 'cfbfc087-c000-55b4-9943-9b7eba1762a1', 'Wonderful Counselor', 'Lord, the Spirit of the Lord rests on Your Son — the Spirit of wisdom and of understanding, the Spirit of counsel and of might — and through Him that same Spirit is available to me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('d30a5e10-56d0-52b9-af1a-c222a5862e20', 'cfbfc087-c000-55b4-9943-9b7eba1762a1', 'In Abundance of Counselors', 'Father, I thank You that You do not leave me without counsel — You have given me Your Spirit, Your Word, and wise people in my life, and today I ask You to activate all of them on my behalf.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('536a9283-f3ce-551f-9205-9556f2042d4d', 'd153b3c3-6713-5585-bb65-12573dc2e124', 'How Long, O Lord?', 'God, I have cried out and I have not seen an answer — and I am asking You honestly: how long? How long do I wait? How long do I keep bringing this to You?
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f66e71f3-56cf-5ce0-979d-15ae27fe5f86', 'd153b3c3-6713-5585-bb65-12573dc2e124', 'Still Praying, Still Waiting', 'Lord, the prayer I have prayed the most has not yet been answered — and I am telling You that honestly, not to accuse You, but because I don''t know how to carry this alone.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1cc33efa-ee5c-558b-bd6f-5646b47f2fd8', 'd1f958be-809c-5e22-a28c-c715285ed87e', 'When the Wait Feels Too Long', 'Father, I will be honest with You: this wait has been painful, and there have been moments I''ve wondered if You forgot.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dc649f21-3255-5f84-aefb-8f30cdbcfc9c', 'd1f958be-809c-5e22-a28c-c715285ed87e', 'In the Waiting', 'God, I am in a season of waiting — and the waiting has been harder and longer than I expected.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6ae02a5f-dbd2-55bc-aa37-c4ae9a02b8cc', 'd4ae8df5-0fd0-56d3-84ce-eda49735375b', 'My Counsellor', 'Father, thank You that You did not leave me to figure life out alone — You sent the Spirit of truth to guide me into all truth, and I am so grateful.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6f02e5e7-94cc-5149-933e-a508fd504a04', 'd4ae8df5-0fd0-56d3-84ce-eda49735375b', 'Led into All Truth', 'Lord, the world offers a thousand voices telling me what is true, what to want, who to be — but only Your Spirit leads me into truth that does not shift or fade.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('543ffaad-4313-55f5-9660-812b6cf757d6', 'd57e7b1b-7690-5fa0-bee3-9c9ac7eb445f', 'Let Them Know You', 'Father, I have no greater joy than to hear that my children walk in truth — let that be the testimony of their lives, no matter what the world around them says.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cecd8098-c411-5516-86e3-c874b064d425', 'd57e7b1b-7690-5fa0-bee3-9c9ac7eb445f', 'A Heritage from the Lord', 'Lord, I thank You for the gift of the children in my life — they are a heritage from You, and I do not take that lightly or for granted.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b69ebd49-29c2-5c71-878a-156e1a4736d0', 'd7cf06e2-331b-5df0-bc82-e829599bc722', 'The Steps of a Good Man', 'Father, You establish the steps of those who delight in You — and when they stumble, they will not fall headlong because You hold them by the hand. Hold my hand at this crossroads.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('de8bf66b-d0d2-56b9-9515-895359b43438', 'd7cf06e2-331b-5df0-bc82-e829599bc722', 'Your Ears Will Hear', 'Lord, whether I turn to the right or to the left, Your ears will hear a voice behind me saying, "This is the way, walk in it" — I am standing at a crossroads, and I am listening for that voice.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('335dc1eb-ac50-5ef1-830e-453758aa32d6', 'd84beca7-7089-57bb-bff2-f4cd6ed2e710', 'A Good Man Leaves an Inheritance', 'Father, I want to be a person who thinks beyond their own lifetime — who plants trees under whose shade they may never sit, who builds something that outlasts them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('36fc6ed3-08f4-52f7-9688-4d941c42a641', 'd84beca7-7089-57bb-bff2-f4cd6ed2e710', 'A Lasting Name', 'Lord, I want my legacy to be a blessing and not a burden — I ask You to help me break every generational cycle that has been passed down through my family line that does not belong in my children''s inheritance.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a5f05bdb-a939-5e23-bc74-b27ae7d38e1f', 'd8669261-9987-5eb9-84aa-2f045e941a4c', 'A Life That Bears Fruit', 'Father, You are clear that good fruit does not grow by striving — it grows by abiding. I want to stay so close to You that my life cannot help but bear what You produce.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('cc8860ae-1b77-5a6a-8e52-9f3568c665dd', 'd8669261-9987-5eb9-84aa-2f045e941a4c', 'Grown, Not Performed', 'Lord Jesus, You said apart from You I can do nothing — and I believe it. I have tried to be patient, to be kind, to be self-controlled apart from You, and it has not lasted.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2aa97609-cc4c-5e94-b281-9bf98de65bd2', 'd8aa3519-984f-53f1-8cc5-aab00a4c581a', 'Clothed in His Armour', 'Lord, I come before You today choosing to be strong — not in my own strength, but in the might of Your power that raised Christ from the dead.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5bfd1d91-f52e-53af-9685-f2bd86c0fc17', 'd8aa3519-984f-53f1-8cc5-aab00a4c581a', 'Dressed for the Day', 'Father, the night is almost over and the day is at hand — I cast off every work of darkness and put on the armour of light as Your Word commands.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('60bd1e4c-f47c-5a7c-8fb6-d847ebf0d42c', 'd9d69077-96dd-5ffd-8c40-15870d90b1fa', 'By His Wounds', 'Lord, Your Word says He was pierced for our transgressions and crushed for our iniquities — and by His wounds, we are healed. I stand on that promise today with every part of my faith.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('970ccb78-2ca4-5bf1-ad5a-d8f260e4a3de', 'd9d69077-96dd-5ffd-8c40-15870d90b1fa', 'Carried in His Body', 'Father, I thank You that Jesus did not just bear my sins on the cross — He bore my sicknesses and carried my diseases, and that finished work is as real and as complete as my forgiveness.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bf423c34-2543-50d3-992b-8d5cc4807278', 'de687ad3-ae25-56ca-a953-ffd8f85f3b9d', 'Held When Fear Overwhelms', 'God, the fear that has come over me feels bigger than what I can manage — it is not a small worry, it is a wave, and I feel like I am being pulled under.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f2d3d8bb-518c-58ff-8cf7-562b9e54802a', 'de687ad3-ae25-56ca-a953-ffd8f85f3b9d', 'When Fear Has the Upper Hand', 'Lord, I am afraid. I am not going to dress it up or spiritualize it — I am genuinely afraid, and I need You right now.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a5fcb331-6d19-5ada-8d94-21af0863bbed', 'e03ec9d6-54e8-5326-a70e-9a0bc8edde3a', 'The Fruit of the Hard Season', 'Father, weeping may endure for a night but joy comes in the morning — I hold onto that promise in this season and declare that what I am experiencing is not the final word.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c36e7a30-9108-5374-a835-64713494099e', 'e03ec9d6-54e8-5326-a70e-9a0bc8edde3a', 'Even Here, You Are Good', 'Lord, this is the prayer that costs something: thank You even for this — for the trial I would not have chosen and the season that has stretched me beyond what I thought I could bear.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7e0a14e8-bb17-5fbf-9b16-703d46b2c416', 'e54ccee8-8f58-5a92-9660-fa71644f6f86', 'Fruit That Remains', 'Lord, I ask for fruitfulness that outlasts me — not just what I produce in my lifetime, but the legacy that remains because I was rooted in You and faithful to what You called me to.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('96223195-855c-5d6a-9b83-32b5ef41a3cb', 'e54ccee8-8f58-5a92-9660-fa71644f6f86', 'A Tree Planted by the River', 'Father, I want to be like the tree in Psalm 1 — planted by rivers of water, bearing fruit in its season, leaves that do not wither — thriving not just in the good seasons but in all of them.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('37e42625-3de5-55b0-bf0a-e68019793d9a', 'e5fa9ed9-8217-5f7b-95c2-37c089c426ea', 'The Forgotten Peoples', 'Father, there are people groups in this world that most Christians have never heard of and will never think to pray for — but You know every name in every tribe and every language.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b4c1b914-4fd3-5d69-afe4-bed30000f4d5', 'e5fa9ed9-8217-5f7b-95c2-37c089c426ea', 'Where Christ Is Not Known', 'Lord, Paul''s ambition was to preach the gospel where Christ was not yet known — and there are still billions of people in that category, peoples who have never once heard the name of Jesus.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a967869f-091b-5d51-b32f-9718812d43d6', 'e6d1601a-561e-521c-a378-907c934afc47', 'Do Not Withhold Your Hand', 'Lord, the weight of watching someone I love walk in the wrong direction is heavy — I bring it to You because I cannot carry it alone and You invited me to cast my cares on You.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b9ce38e6-55cb-5d70-9865-d452e59c1f54', 'e6d1601a-561e-521c-a378-907c934afc47', 'They Are Coming Home', 'Father, I come before You with a name on my heart — someone who has walked away, who is far from You right now, and for whom I refuse to stop praying.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1e7a8fcd-ad41-5879-9cf2-e561d0ee885c', 'e6de4475-aba8-514b-91ee-c612a609ef73', 'God, I Am Angry', 'Lord, I am angry — and I am bringing it to You because I don''t know what else to do with it, and I refuse to let it fester in silence.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('5448d0f1-d8b0-5271-8ec1-ad22070d1b6e', 'e6de4475-aba8-514b-91ee-c612a609ef73', 'Honest Before You', 'Father, the Psalms are full of people bringing their rage and their grief to You without cleaning it up first — I want to do the same.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1f8c7134-976f-51c0-9882-ba86826f7e8b', 'e825e06c-3929-50ac-bc5c-efefb28ab23d', 'The Night Is Yours Too', 'Father, the darkness is not dark to You — the night shines like the day, and so I come to You now as the day ends, knowing You are no less present in the quiet.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('709c89a0-9b9e-5c65-aa74-c9374484923a', 'e825e06c-3929-50ac-bc5c-efefb28ab23d', 'On My Bed I Remember You', 'Lord, on my bed I remember You — I meditate on You through the watches of the night, and my soul clings to You because Your right hand upholds me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('16626fea-c7ae-5fa7-821f-e23ab6753474', 'e8b5d8c4-9487-52d6-9a24-6c1bc6953672', 'Breaking Generational Patterns', 'Father, I thank You that the cross did not just deal with my personal sin — it broke the power of every inherited pattern, every cycle, and every generational curse in my bloodline.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('1d6b9f29-00a1-537c-86c0-91bfe4124bb9', 'e8b5d8c4-9487-52d6-9a24-6c1bc6953672', 'Redeemed from Every Curse', 'Lord, Your Word declares that Christ became a curse for me so that I could receive the blessing of Abraham — I stand on that finished work today with my whole heart.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('8bb231e0-cfd5-5cf8-92ac-4b7a3a34106d', 'e95168db-5346-580a-8cd4-e6176937f442', 'Made for Good Works', 'Father, You appointed Jeremiah before he was born and called him before he came out of the womb — I believe You did the same for me, and I want to stop living below that calling.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b9ae3704-d3af-5fe6-8124-a1fd17dc95f3', 'e95168db-5346-580a-8cd4-e6176937f442', 'Before You Were Born', 'Lord, You knew me before You formed me in the womb — my existence is not an accident, my life is not a mistake, and I was not born without intention.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a6bf36f4-0644-5dbd-883a-8d249bd3fad0', 'ea1538c3-a51c-5a71-86d3-ca29b9e4e7c5', 'Living from the Other Side of the Cross', 'Father, I am a resurrection person — I live on the other side of the empty tomb — and I want my daily life to reflect that, not just my theology.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('f59bc000-d6e0-5985-a8d7-c855a8209560', 'ea1538c3-a51c-5a71-86d3-ca29b9e4e7c5', 'Death Is Not the End', 'Lord Jesus, You are the firstfruits of the resurrection — the first and not the last — and because You rose, death does not get the final word over me or the people I love.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0d482112-3a81-5b0d-a899-83b879bea507', 'eaf07b9c-f366-5f37-9bec-887077650cb7', 'You Have Never Let Me Down', 'Lord, I testify today — You have never let me down. Not once. There were times I misread Your silence as absence, but looking back I see Your faithfulness threaded through every season.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e7b33d61-750d-5d19-8ad7-0aeac5120409', 'eaf07b9c-f366-5f37-9bec-887077650cb7', 'From One Season to the Next', 'Father, I will sing of Your steadfast love forever and declare Your faithfulness to all generations — because Your faithfulness is not just a doctrine to me, it is the story of my life.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0efa1063-c291-5ba6-bd5c-fccc1396bd9d', 'ec3097df-8e52-5457-945e-d570513557d0', 'No Provision for the Flesh', 'Lord, I know that what I feed grows and what I starve weakens — and I confess I have been feeding things that do not deserve to grow in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2f686e1f-087c-5606-b29d-00d0adfb5914', 'ec3097df-8e52-5457-945e-d570513557d0', 'Walk in the Spirit', 'Father, Your Word says to walk in the Spirit and I will not gratify the desires of the flesh — I ask You today to fill me afresh so that what is stronger takes over what is weaker.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('17926631-f9dc-5991-a4ca-edb84d62ecbb', 'ecf09a1b-89b7-5831-baf3-d344cd3cb21e', 'Walk Me Through', 'Lord, I do not want to force open doors that You have not opened — give me the patience to wait on Your timing and the faith to walk boldly when You say go.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c5610af4-de7f-5a8c-8b2b-0d866694a2a6', 'ecf09a1b-89b7-5831-baf3-d344cd3cb21e', 'The Key of David', 'Father, You are the One who holds the key of David — what You open, no one can shut, and what You shut, no one can open. I trust You with the doors in my life.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2fe7af25-6d6f-51d8-af1a-32aceeba6670', 'ecf0dc93-272f-56f4-8e9e-2c3432c9f253', 'Breaking the Pattern', 'Father, I see the pattern now — the same triggers, the same reactions, the same regrets — and I am tired of running the same loop.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('7f8c47f5-ec4f-5a2d-b388-6583ee3e007b', 'ecf0dc93-272f-56f4-8e9e-2c3432c9f253', 'Slow Me Down', 'Lord, I react too fast — the anger rises and before I''ve thought a single thing through, I''ve already spoken or acted in a way I will regret.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a1bde31d-e18a-505d-879a-0855af0dcf3c', 'ef564d3c-b130-516a-85b2-1fae941ad9d8', 'Casting It All on You', 'Father, You tell me to cast all my anxiety on You, because You care for me — every word of that sentence is a gift I need to receive today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('efb9eb8d-8e66-5770-8bea-87032ab9056e', 'ef564d3c-b130-516a-85b2-1fae941ad9d8', 'The Practice of Letting Go', 'Lord, I know what Your Word says — I know I am supposed to cast my cares on You. But I confess that I keep picking them back up.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('00fa3ed0-42c7-596a-a008-0eefcc5f5803', 'efa1cd7e-ded2-5e90-8aef-c66dd104aa71', 'The Lord Gives Wisdom', 'Father, wisdom does not come from accumulating information — it comes from You, and from the kind of relationship with You where I am close enough to hear what You are saying.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c576c1af-432f-5e1b-a045-e68ad6b40a13', 'efa1cd7e-ded2-5e90-8aef-c66dd104aa71', 'Ask and It Will Be Given', 'Lord, if any of us lacks wisdom, we should ask You, who gives generously to all without finding fault — and so I ask, without doubting, because You promised generously and without reproach.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('96aa42cb-fbac-5d3b-8f53-0bbb1a4ad63a', 'f0765853-807c-585c-b77a-63c9a87ebdf0', 'Multiplied in Every Way', 'Lord, I believe in a God of multiplication — not a God of barely enough, not a God of just getting by, but a God who multiplies loaves for thousands and whose resources never run dry.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('e4324f23-7b06-5cf7-a93d-abba12e504ba', 'f0765853-807c-585c-b77a-63c9a87ebdf0', 'A Thousand Times More', 'Father, You said to Israel — may the Lord make you a thousand times more numerous than you are — and that same heart of abundance is Yours toward me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('60ad5dd7-3117-5ac3-b950-a919ad0ba175', 'f33d281f-2acb-55e9-8d61-85e8064eb971', 'A Peace Beyond My Own Understanding', 'Lord, I bring You everything I have been carrying — the worry, the uncertainty, the weight I have been trying to manage on my own.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bd31dd05-3559-555c-a8c1-7d04752f5c10', 'f33d281f-2acb-55e9-8d61-85e8064eb971', 'When I Cannot Find Peace on My Own', 'Father, I confess that I have been reaching for peace in all the wrong places — in distraction, in control, in trying to think my way through what only You can resolve.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('bb29852b-c4b8-5f97-b84d-ce0a0d259a26', 'f4555720-df72-5c7c-8923-6dfc3725052d', 'When I Am Running Dry', 'Father, I am depleted — I have been giving and giving and I am not sure I have anything left — and I am asking You to fill me before I try to pour out again.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c8d3458e-f8a6-51e6-991f-b679dd1714b5', 'f4555720-df72-5c7c-8923-6dfc3725052d', 'Love Is a Choice', 'Lord, I need to be honest — love feels hard right now — the person I am supposed to love is difficult and I am running on empty and I need You to refill what is depleted in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('3691814b-90b0-5388-bdd6-1a593e2b59b9', 'f4afeebf-e40c-540b-a340-9f6d7f317016', 'Blessing Those Who Have Hurt You', 'Father, Your kingdom runs on a logic that is completely different from the world''s — bless those who curse you, do good to those who hate you.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('82109778-3a88-53de-b2fe-b6e473e9d5da', 'f4afeebf-e40c-540b-a340-9f6d7f317016', 'I Don''t Want to Pray for Them — But I Will', 'God, You told me to pray for those who have wronged me — and I want to obey that, even though there is a part of me that doesn''t want to.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b266c86d-958a-5cb3-b2c4-a6ce191c5ee7', 'f55211a2-9229-547b-a148-06099a932d0c', 'Salvation in This House', 'Lord, I am standing in the gap for family members who do not yet know You — I refuse to stop praying, I refuse to stop believing, I refuse to lose hope for their souls.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('dc91b142-d166-550b-ba0a-81f369938e4f', 'f55211a2-9229-547b-a148-06099a932d0c', 'Honor and Care', 'Father, I lift up my extended family before You today — the parents, the siblings, the grandparents, the cousins and uncles and aunts who are part of the story You are writing through my bloodline.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('0c10a01c-4910-593c-a35e-9c1af34ffb29', 'f55d18c3-f1d6-59bb-8c00-650f25b2cc02', 'Peace That Passes Understanding', 'Father, tension in relationship is one of the hardest things to carry — I bring before You the conflict that is weighing on me today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b9e695d1-c0f9-574c-936f-2487d4bd01ee', 'f55d18c3-f1d6-59bb-8c00-650f25b2cc02', 'Do Not Let the Sun Go Down', 'Lord, You know that conflict is hard — even in love, disagreement can wound, and I bring this tension before You before I let it take root.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('37c639e3-f78c-51fc-9d7d-51646f0e857f', 'f80983af-4d3c-5826-b159-fb8b9a43e2d3', 'You Heard Me', 'Lord, I sought You and You answered me — the God of heaven stopped and listened when I called, and that is not a small thing.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('6dc1f36b-9ed9-5106-a6fe-4fbff35aa128', 'f80983af-4d3c-5826-b159-fb8b9a43e2d3', 'I Remember What You Did', 'Father, I will remember the deeds of the Lord — I will meditate on Your wonders and hold before my heart the specific moments when You answered, when You came through, when You showed up.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('2dafb3d9-4530-54a7-8895-6047f06713a3', 'f905dc3e-4637-52d6-a663-2d4e364223b4', 'Called Where I Am', 'Lord, I do not have to be in full-time ministry to be in full-time service — I am called right where I am, to the people in the building where I work every day.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('b0d89af2-2695-5368-b4a3-32a9b26b0a96', 'f905dc3e-4637-52d6-a663-2d4e364223b4', 'Let Your Light Shine', 'Father, I go into my workplace today not just as an employee or a professional, but as Your representative — let my light shine in this place so that people see You in me.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('920ff808-0bcf-5b28-b352-c0bb42d45e27', 'fb5dbbe9-f1cb-5395-93fa-3dd6dd4077a7', 'The Peace of This City', 'Father, You told Your people in exile to seek the peace and prosperity of the city where You placed them — and I take that mandate seriously. I am praying for this city today.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a594010a-64ad-5a87-804f-1042dde485b8', 'fb5dbbe9-f1cb-5395-93fa-3dd6dd4077a7', 'A City Rebuilt', 'Lord, I pray for peace in this city — in its streets, in its homes, in the places where tensions run highest and hope runs lowest.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('940ce313-7979-504e-9bb3-05159f8b950d', 'fc1e96b2-baa5-58a1-8549-955395065be4', 'Pray for the Peace of Jerusalem', 'Father, You have not abandoned Your covenant with Israel — Your gifts and callings are irrevocable, and I stand in prayer for the Jewish people with that truth as my foundation.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('eecb85a8-a22a-5f4d-9d38-229c2d3629d6', 'fc1e96b2-baa5-58a1-8549-955395065be4', 'Until All Israel Is Saved', 'Lord, I believe Your Word that all Israel will be saved — and I pray toward that promise with faith, knowing that history is moving toward the moment You have planned.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('09a5df23-c85f-5bca-9492-e02633ecca4d', 'fd24aa57-ee84-52f8-bfde-325a4ddafa09', 'Step by Step', 'Father, Your Word says if I walk in the Spirit, I will not fulfil the desires of the flesh — so today I choose to walk. Not in my own direction, but Yours.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('a67cc008-760d-5fdd-a4f0-5206be3ef0ed', 'fd24aa57-ee84-52f8-bfde-325a4ddafa09', 'Kept in Step', 'Lord, there is a war within me between the flesh and the Spirit — and I am not strong enough to win it on my own. I need You to do in me what I cannot do for myself.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('00115457-59b9-5828-b580-85992b3a5d19', 'ff0d90f8-3933-5f28-8293-719ceec0fbdc', 'Overtaken by Blessing', 'Father, Your Word says that all these blessings will come upon me and overtake me if I walk with You — I receive that Word today and I align my life with it.
INSERT INTO public.prayers (id, topic_id, title, body, author, is_classic) VALUES ('c05111b0-03a0-5dde-a449-7d34be4eb484', 'ff0d90f8-3933-5f28-8293-719ceec0fbdc', 'The Head and Not the Tail', 'Lord, You said I shall be the head and not the tail, above and not beneath — let me walk in the reality of that promise and not just know it as a verse.
INSERT INTO public.scriptures (id, book, book_code, chapter, verse_start, verse_end, reference) VALUES ('54ee320a-e633-5126-9bb2-993ade85c88c', '1 Corinthians', '1CO', 1, 31, NULL, '1 Corinthians 1:31') ON CONFLICT ON CONSTRAINT scriptures_unique_ref DO NOTHING;
